INSERT INTO `field_context` (`pages_id`, `data`, `sort`, `number`, `text`) VALUES('1638', '50', '6', '7', '1023:<p>Laubverblüte Stauden und die Reste vom Gemüsebeet sind Nahrung überwinterungs- und kinderstuben jagdreviere und verstecke</p>');
INSERT INTO `field_context` (`pages_id`, `data`, `sort`, `number`, `text`) VALUES('1632', '51', '0', '1', '1023:<p>Ein Störungsbeispiel mitten aus dem Alltag: Du räumst im Garten und ein Eimer bleibt in einer Gartenecke stehen. Du vergisst ihn lange, als er wieder nützlich wird stellst Du beim hochheben fest: Die Grasnarbe hat sich zurückgezogen, durch die Störung ist ein neues kleines Mini-Biotop entstanden. Die Bewohner wuseln irritiert von Sonnenlicht weg.</p>');
