INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2151', 'pxl_20251226_205659372pix.jpg', '0', '[\"\"]', '2026-03-24 09:59:57', '2026-03-24 09:58:46', '{\"uploadName\":\"PXL_20251226_205659372pix.jpg\",\"_136\":\"Rauhnachtsritual, ged\\u00e4mptes Licht. ausgef\\u00fcllter Zettel, Kerze, Palo Santo und Affirmationskarten zum ziehen.\",\"_137\":\"Seit einigen Jahren zelebriere ich die Rauhn\\u00e4chte. Im Tiefsten Winterpunkt des Naturrhytmus sind sie nat\\u00fcrlicherweise entschleunigend.\",\"_149\":\"Seit einigen Jahren zelebriere ich die Rauhn\\u00e4chte. Im Tiefsten Winterpunkt des Naturrhytmus sind sie nat\\u00fcrlicherweise entschleunigend.\",\"_134\":\"2025\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2025 125_1120\"}', '836133', '41', '41', '2357', '1696', '1.39');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2151', 'tagetes-1.png', '1', '[\"\"]', '2026-03-22 15:19:37', '2026-03-22 15:14:44', '{\"uploadName\":\"Tagetes-1.png\",\"_136\":\"Extreme Nahaufnahme, Fraktale, unerkennbar auf den ersten Blick. Gelb und drumherum rot-orange. Tagetes-Bl\\u00fcte, Mikroskopaufnahme.\",\"_137\":\"Was siehst Du? \\\"Die kleinen Dinge im Leben, die sind nicht klein.\\\"\",\"_149\":\"Was siehst Du? \\\"Die kleinen Dinge im Leben, die sind nicht klein.\\\" Tagetes-Bl\\u00fcte, Mikroskop-Aufnahme.\",\"_134\":\"2021\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2021 125_1120\"}', '1242847', '41', '41', '1920', '1080', '1.78');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2156', 'pxl_20260318_163658741.jpg', '0', '[\"\"]', '2026-03-22 15:37:35', '2026-03-22 15:31:38', '{\"uploadName\":\"PXL_20260318_163658741.jpg\",\"_136\":\"Kursmitte des Stuhlkreises. Kerze und Gegenst\\u00e4nde. Ein Kreis ist darum gelegt aus den 12 Prinzipien.\",\"_137\":\"\",\"_149\":\"Bei Kursen immer dabei: Die 12 Prinzipien von David Holmgren.\",\"_134\":\"2026\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2026 125_1120\"}', '1474147', '41', '41', '2309', '1731', '1.33');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2156', '0.jpg', '1', '[\"\"]', '2026-03-22 15:37:35', '2026-03-22 15:31:38', '{\"_136\":\"Gestaltungsprinzipien als buntes Poster und \\u00dcbersicht. In der Mitte die Ehiken und im \\u00e4u\\u00dferen Kreis angeordnet die bekannten Icons mit den Prinzipien.\",\"_137\":\"z.b. Schnecke als Icon bei \\\"Kleine und langsame L\\u00f6sungen\\\"\",\"_149\":\"Gestaltungsprinzipien als buntes Poster.\",\"_134\":\"\",\"_144\":\"PermaculturePrinciples.com\",\"_138\":\"https:\\/\\/permacultureprinciples.com\\/resources\\/free-downloads\\/\",\"_125\":[1870],\"ix\":\"125_1870\"}', '315322', '41', '41', '2378', '1680', '1.42');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2160', 'pxl_20241121_160003719.jpg', '0', '[\"\"]', '2026-03-22 16:04:25', '2026-03-22 15:59:35', '{\"uploadName\":\"PXL_20241121_160003719.jpg\",\"_136\":\"Freiburg, Foto auf den Boden mit roten Winterstiefeln. Ein filigranes Mosaikbild, in der Mitte ein Buch und H\\u00e4nde die darauf zeigen.\",\"_137\":\"Was ist echtes Wissen und wie erlangen wir dieses im Prozess?\",\"_149\":\"Was ist echtes Wissen und wie erlangen wir dieses im Prozess? Bild: Mosaik in der Innenstadt Freiburg.\",\"_134\":\"2024\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2024 125_1120\"}', '1185302', '41', '41', '2309', '1731', '1.33');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2160', 'pxl_20260322_144432780pix.jpg', '1', '[\"\"]', '2026-03-22 16:04:25', '2026-03-22 15:59:35', '{\"uploadName\":\"PXL_20260322_144432780pix.jpg\",\"_136\":\"gelegte Karten vom Permakultur-Designprozess. 1. ganzheitliches beobachten. 2. komplex denken. 3. flexibel planen. 4. verantwortlich handeln.\",\"_137\":\"in der Mitte ein St\\u00fcck holz mit den gelb angemalten Buchstaben: FEIERN!\",\"_149\":\"Feiern - hei\\u00dft leben und den Moment zu w\\u00fcrdigen. BADUZ endet mit: Zelebrieren.\",\"_134\":\"2026\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2026 125_1120\"}', '1045425', '41', '41', '2144', '1864', '1.15');
