INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2173', 'pxl_20241220_105143339.jpg', '1', '[\"\"]', '2026-03-22 17:37:10', '2026-03-22 17:31:52', '{\"uploadName\":\"PXL_20241220_105143339.jpg\",\"_136\":\"Bild Nahaufnahme Hand an einem Kiesstrand auf R\\u00fcgen, im Hintergrund viele grobe Steine. In der Hand ein ganz eigentl\\u00fcmlich geformter\",\"_137\":\"Handschmeichelnder Stein. Mein bester, weil sehr individueller Redegegenstand.\",\"_149\":\"Mein bester, weil sehr individueller Redegegenstand f\\u00fcr einen tiefgehenden Check-In. Gefunden auf R\\u00fcgen.\",\"_134\":\"2024\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2024 125_1120\"}', '886501', '41', '41', '1732', '2309', '0.75');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2177', 'kleines_hochbeet_zuhause.jpg', '0', '[\"\"]', '2026-03-22 17:51:00', '2026-03-22 17:45:11', '{\"uploadName\":\"kleines Hochbeet zuhause.jpg\",\"_136\":\"Kleine Intensive Systeme sich vielen Einfl\\u00fcssen ausgesetzt: HIer etwa ein Windkorridor. Zu sehen ein Hochbeet aus aufgestellten Betonplattten.\",\"_137\":\"Im Hochbeet ein intensiver Gem\\u00fcse-Mischkultur-Mix auf kleinstem Raum. Ringelblumen, Bohnen, K\\u00fcrbis, M\\u00f6hre Fenchel, Lauch etc.\",\"_149\":\"Kleine Intensive Systeme sich vielen Einfl\\u00fcssen ausgesetzt: HIer etwa ein Windkorridor.\",\"_134\":\"2023\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2023 125_1120\"}', '1682563', '41', '41', '2309', '1731', '1.33');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2177', 'sektorrose_beispiel_2x.png', '1', '[\"\"]', '2026-03-22 17:51:00', '2026-03-22 17:45:11', '{\"uploadName\":\"Sektorrose Beispiel_2x.png\",\"_136\":\"Sektorrose gemalt: Auf Transparentpapier ist eine \\\"Zielscheibe\\\" mit 4 Ringen. Innerer Kreis: Himmelsrichtungen. 1. Ring: Sonnenverlauf Winter-\",\"_137\":\"Sommersonne. 2. Ring Wind (links, S-SW). 3. Ring Einfahrt und Pflegeweg. 4. Ring: Spazierg\\u00e4nger (SO-NW)\",\"_149\":\"Eine Sektorieung macht viele immaterielle und bewegliche Einfl\\u00fcsse f\\u00fcr uns sichtbar.\",\"_134\":\"2021\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2021 125_1120\"}', '2024998', '41', '41', '2340', '1708', '1.37');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2181', '20190525_194614.jpg', '0', '[\"\"]', '2026-03-22 18:55:18', '2026-03-22 17:54:47', '{\"_136\":\"Inspiration. Vor einem Zirkuszelt (Veranstaltung) steht ein K\\u00fcbel, darin Gras und einige unauff\\u00e4llige Beikr\\u00e4uter. In dem Topf steckt ein gro\\u00dfes\",\"_137\":\"gelbes Schild: \\\"Sch\\u00f6nstes Fleckchen Wiese auf dem ganzen Tempelhofer Feld\\\"\",\"_149\":\"Inspiration. Was ist normal?\",\"_134\":\"2019\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2019 125_1120\"}', '473988', '41', '41', '1500', '1953', '0.77');
INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2218', 'dauergemuese_2x.png', '0', '[\"\"]', '2026-03-25 08:28:16', '2026-03-25 08:26:38', '{\"uploadName\":\"Dauergem\\u00fcse_2x.png\",\"_136\":\"Dauergem\\u00fcse kann sehr vielf\\u00e4ltig sein und pflegeleicht! \\u00dcbersicht mit Meerkohl, Tablilien, Guter Heinrich, Spargel, Hopfen, Rhabarber, Winter-\",\"_137\":\"heckenzwiebel und Kartoffeln. Bilder von Wikicommons zusammengestellt.\",\"_149\":\"Dauergem\\u00fcse, vielf\\u00e4ltig und pflegeleicht! \\u00dcbersicht: Meerkohl, Tablilien, Guter Heinrich, Spargel, Hopfen, Rhabarber, Winterheckenzwiebel, Kartoffeln.\",\"_134\":\"\",\"_144\":\"\",\"_138\":\"\",\"_125\":[]}', '2905211', '41', '41', '2462', '1404', '1.75');
