INSERT INTO `field_long_description` (`pages_id`, `data`) VALUES('1728', 'Wie können wir verbunden leben? Wie begegne ich mit Liebe meinem Lebensfluss? Wie fühlt sich dein natürliches, zyklisches Leben in Balance an?');
INSERT INTO `field_long_description` (`pages_id`, `data`) VALUES('2120', 'Ein Garten voller Mahlzeiten und alltäglichen Überraschungen! - Du sehnst dich nach einem zukunftsfähigen Wandel? Dann bist du hier genau richtig!');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1', 'Herrliche Permakultur ist die Webseite von Carolin Herrlich. Sie gestaltet soziale Räume, Alltag und Gärten mit sozialer und zyklischer Permakultur.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1109', 'Ein Überblick über die Grundlagen der Permakultur: Einstieg, Ethik, Prinzipien und Leitfäden für eine nachhaltige und regenerative Gestaltung.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1117', 'Steige ein in die Welt der Permakultur, verstehe Grundlagen und erkenne Zusammenhänge aus neuer Perspektive.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1151', 'Permakultur-Beratungen online & vor Ort, 1:1 oder in Gruppen. Ganzheitliche, praxisnahe Impulse für Gärten, Projekte und nachhaltige Entwicklung.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1168', 'Lerne die verschiedenen Aspekte permakultureller Designprozesse kennen: lebendige Gestaltungsprozesse zu komplexen Fragestellungen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1171', 'Tauche ein in die ganzheitliche Gestaltung, um mit systemischer Vernetzung auf Basis der Permakultur-Ethik zu kreieren.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1175', 'Verstehe die tiefen Zusammenhänge des Gestaltens nach dem Vorbild natürliche Ökosysteme mithilfe von zyklischem Denken und Gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1178', 'Mit Permakultur-Methoden dein eigenes resilientes System im Alltag designen. Hol dir hier Inspirationen zum Start in deinen nachhaltigen Alltag.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1181', 'Erfahre, wie du mithilfe sozialer Permakultur-Methoden Projekte, Gemeinschaften und soziale Prozesse unterstützt und auf mehreren Ebenen gestaltest..');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1184', 'Lerne über die resiliente Gestaltung von Landflächen nach dem Vorbild der Natur für kreislaufbasierte, essbare und artenreiche Paradiese und Gärten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1187', 'Ein Überblick über verschiedene Arten von Werkzeugen der Permakultur, mit denen nachhaltige Projekte geplant, gestaltet und umgesetzt werden können.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1223', 'Die Ethik der Permakultur bildet mit der Sorge für die Erde, der Sorge für die Menschen und gerechtes Teilen die Grundlage für nachhaltiges Handeln.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1244', 'Hier findest du eine kurze Zusammenfassung des Kapitels zu den Grundlagen der Permakultur mit Themen wie Ethik, Prinzipien und erste Schritte.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1268', 'Eine wachsende Liste von Werkzeugen in der Permakultur, mit denen nachhaltige Projekte geplant, gestaltet und umgesetzt werden können.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1297', 'Inspiration, Wissen und Geschichten aus der Permakultur: entdecke ganzheitliches Denken, Naturprinzipien und kreative Lösungsansätze.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1307', 'Erlebe Permakultur praktisch mit Kursen zu Naturgartengestaltung, Zyklischer Permakultur und Selbstversorgung für Anfänger:innen und Fortgeschrittene.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1338', 'Praktische und anschauliche Permakultur-Werkzeuge zum Herunterladen für deine eigenen, individuellen Permakultur-Erfahrungen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1349', 'Bekomme einen Einblick in Vision und Vita von Carolin Herrlich, der Person hinter Herrliche Permakultur.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1371', 'Eine Übersicht über die verschiedenen Felder, in denen Carolin Herrlich als Herrliche Permakultur tätig ist und angefragt werden kann.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1377', 'Nimm Kontakt auf für Beratung, Projekte oder Fragen rund um Permakultur und ganzheitliche Gestaltung – ich freue mich auf dich.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1383', 'Prozessmodelle geben uns einen klar strukturierten Fahrpla, um resiliente Ökosysteme zu designen');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1389', 'Prinzipien der Permakultur helfen, die Ethik in den Gestaltungsprozess aktiv miteinzubeziehen und so Systeme nachhaltig zu gestalten und zu nutzen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1395', 'Eine Übersicht über permakulturelle Prozessmodelle und ihre unterschiedlichen Schwerpunkten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1401', 'Die Superpower der Permakultur vorgestellt: das Beobachten. Entdecke, warum das immer der erste Schritt ist und wie es dein Sehen bereichern kann.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1407', 'Die umfangreiche Analyse deiner Beobachtungen aus einem Permakultur-Projekt hilft dir, diese einzuordnen und die richtigen Schlüsse daraus zu ziehen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1413', 'Übersetze die Ergebnisse deiner Beobachtungen und Analysen mit ausgewählten Gestaltungsmethoden zielgerichtet in ein nachhaltiges Konzept.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1419', 'Entdecke, wie du einen Gestaltungsentwurf umsetzt und wie du durch durchdachte Umsetzung langfristig Freude daran hast.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1425', 'Entdecke ganzheitliche Gestaltung mit dem Vorbid der Natur. Wo können wir uns clevere Lösungen abschauen und in nachhaltige Gestaltungen integrieren?');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1431', 'Hier lernst Du, welche Aspekte wichtig sind, um langfristiges, also echtes nachhaltiges Denken und Handeln einzuüben mithilfe von verbundenem Denken.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1437', 'Verstehe, warum Ambivalenzen und Übergänge unvermeidlich sind und wie du inklusiver mit ihnen umgehen kannst.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1444', 'Hier findest du eine kurze Zusammenfassung des Kapitels zu Designprozessen der Permakultur mit vertiefter Info zu den einzelnen Prozessschritten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1448', 'Gestalte dein Leben ganzheitlich und zyklisch: entdecke Permakultur, Kreisläufe und nachhaltige Lösungen für mehr Balance, Verbundenheit und Harmonie.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1454', 'Entdecke das 8-Schilde-Modell für zyklische Naturverbindung, klare Prozesse und nachhaltige Entwicklung für Alltag, Gruppen und Permakultur-Projekte.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1460', 'Entdecke natürliche Zyklen in der Permakultur. Saisonalität, Sukzession und Wachstum verstehen und für nachhaltige Gärten und bewusstes Leben nutzen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1466', 'Finde deinen individuellen Rhythmus mit dem 8-Schilde-Modell: zyklisch leben, Fokus, Pause & Reflexion für mehr Balance, Resilienz und Lebendigkeit.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1472', 'Inspiriere dich mit diesen Einblicken in verschiedenste reale Permakultur-Projekte und lerne die Vielfalt der Permakultur kennen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1489', 'Nimm Probleme aus einer anderen Perspektive wahr und finde so zu deren Lösung.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1495', 'Systemisches Denken ist essenzieller Bestandteil der Permakultur. Finde heraus, was es so wertvoll für die Gestaltung nachhaltiger Strukturen macht.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1532', 'Nutze die Permakultur-Ethik, um Mitgefühl zu entwickeln und bewusst dein Leben, Verhalten und Umfeld nachhaltig gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1538', 'Mit natürlicher Selbstfürsorge, Bewegung, Ernährung und Achtsamkeit deinen Körper stärken.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1544', 'Erlebe Permakultur in der Küche: nachhaltig kochen, Vielfalt genießen, Abfall vermeiden, regionale Zutaten nutzen und kreative, regenerative Küche.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1550', 'Gestalte deinen Wohnraum nachhaltig: Ressourcen schonen, Gemeinschaft fördern und Permakultur-Prinzipien für ein bewusstes Zuhause anwenden.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1556', 'Unterwegs bewusst erleben: langsam reisen, Fahrrad und Mikroabenteuer nutzen und neue Perspektiven für ein nachhaltiges Leben gewinnen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1562', 'Gestalte deinen Alltag bewusst: Rituale, Rhythmus und Wertschätzung verbinden, um Fülle und Achtsamkeit für eine nachhaltige Alltagskultur einzuladen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1568', 'Hier findest du eine kurze Zusammenfassung des Kapitels zu den Grundlagen der zyklischen Permakultur mit Themen wie Prozesshaftigkeit und Zirkularität');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1572', 'Hier findest du eine kurze Zusammenfassung des Kapitels zu gelebter Permakultur im Alltag, mit Themen wie innere Landschaft und Zuhause gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1576', 'Erkunde und kultiviere deine innere Landschaft. Mit Achtsamkeit, Mitgefühl und Intuition gestaltest du dein Leben bewusst und nachhaltig im Außen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1582', 'Fördere wertschätzende Interaktion durch aktives Zuhören, transparenter Kommunikation und gemeinsamer Gestaltung vertrauensvoller Gesprächsräume.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1588', 'Lerne die Grundlagen kennen, um sensible und sozial orientierte Orte für Begegnung, Vertrauen und Gemeinschaft zu schaffen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1594', 'Gestalte soziale Prozesse, indem du Räume für Verbindung und Gemeinschaft öffnest und Begegnung bewusst förderst.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1600', 'Kultur als Transformationskraft: Werte, Rituale und bewusstes Handeln gestalten Alltag, Gemeinschaft und nachhaltige Zukunft aktiv mit.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1606', 'Hier findest du eine kurze Zusammenfassung des Kapitels zu sozialer Permakultur, mit Themen wie Räume schaffen und Begegnung gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1610', 'Naturnahe Gärten nach Möglichkeiten und Bedürfnissen mit Hilfe von essbaren Pflanzen, Begegnungsräumen und nachhaltigen Konzept gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1616', 'Ein Designprozess mit beobachten, analysieren, gestalten und umsetzen für naturnahe, nachhaltige Gärten voller Vielfalt, Kreisläufe und Gartenoasen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1622', 'Lass dich inspirieren von einer kuratierten Sammlung an Elementen und Pflanzen, um einen Garten nach Permakultur-Prinzipien zu gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1628', 'Lebendige Gärten gestalten, in denen für alle Lebewesen eine Heimat geschaffen wird und friedliche, vielfältige Koexistenz möglich ist.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1634', 'Wie kann ein Naturgarten aussehen, in dem Vielfalt durch heimische Pflanzen und Wildtiere im Vordergrund steht? Was macht ihn so nachhaltig?');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1640', 'Hier findest du eine kurze Zusammenfassung des Kapitels zur ganzheitlichen Gestaltung mit Themen zu Perspektivwechsel und Systemik.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1653', 'Lerne prozesshaft zu leben, indem du natürliche Rhythmen, Permakultur und geduldige Entwicklung nutzt.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1659', 'Eine kurze Zusammenfassung des Kapitels zu grüner Permakultur, mit Themen wie Naturgarten, essbare Landschaften und lebendigen Räumen.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1750', 'Unterstütze neue Strukturen lokal und global: Nachhaltig handeln, Gemeinschaft fördern, Ressourcen teilen und zukunftsfähige Projekte aktiv gestalten.');
INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1756', 'Essbare Pflanzen gezielt in Waldgärten und Agroforsten einsetzen und dadurch essbare Landschaften kreiern.');
