INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '12', '0', '1023:<p>Nordosten</p>', '1023:<p>Impuls</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '13', '1', '1023:<p>Osten</p>', '1023:<p>Orientierung</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '14', '2', '1023:<p>Südosten</p>', '1023:<p>Neugierde</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '15', '3', '1023:<p>Süden</p>', '1023:<p>Fokus</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '16', '4', '1023:<p>Südwesten</p>', '1023:<p>Entspannung</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '17', '5', '1023:<p>Westen</p>', '1023:<p>Gemeinschaft</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '18', '6', '1023:<p>Nordwesten</p>', '1023:<p>Reflexion</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1721', '19', '7', '1023:<p>Norden</p>', '1023:<p>Überblick</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '28', '0', '1023:<p>Ziel</p>', '1023:<p>Die Mitarbeiter des Palliativteams äußern ihre Wünsche und Bedürfnisse hinsichtlich eines Team-Abschiedsrituals für Verstorbene Patienten. Wir lernen uns besser kennen und bilden eine gemeinsame Kultur aus.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '29', '1', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>Alpha-BADUZ</p>\n\n<p>People Care: bei der Begleitung von nicht mehr heilbaren Menschen ohne professionelle psychologische Unterstützung brauchen wir Rituale um zu verarbeiten.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '30', '2', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Klares Vorgehen bei der Vorbereitung und dem Setting dass ich schon sehr viel von der neuen Kulturschaffung umsetze. Ich sah es bei der Reflexion mit den sozialen Looby-Prinzipien. Ein Feldversuch um neue Kultur zu schaffen-angelegt auf Basis der Permakulturwerkzeuge. Ich habe damit nicht nur mit der Gruppe die Antwort auf eine Frage gesucht, sondern im tieferen Sinne eine gemeinsame neue Kultur inspiriert, die sich entwickeln kann.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '31', '3', '1023:<p>AHA´s und Gestaltung</p>', '1023:<p>Systemisches konsensieren und Moderation in den 8 schilden hat wunderbar funktioniert wir kamen gemeinsam ins Träumen und es wurde deutlich welchen Konsens die Gruppe findet Punkt aha alle Kollegen haben sich gegenseitig gehört in ihren Bedürfnissen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '32', '0', '1023:<p>Ziel</p>', '1023:<p>Planung eines Alters- und rollstuhlgerechten Schrebergarten mit viel Altbestand und Material für zwei Generationen. Ein bunter, strukturreicher Schrebergarten für Individualität, Vielfalt und Gemeinsamkeit.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '33', '1', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>OBREDIMET und</p>\n\n<p>People care-nur gemeinsam können wir stabile, resiliente Systeme kreieren!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '34', '2', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Dreh- und Angelpunkt war der Besuch und das Gespräch mit den Menschen vor Ort. Im Design habe ich Schwächen zu stärken verwandelt! Viel verstreutes Material wird zu Struktur und gemeinsamen Projekten. Zudem hat mich das OBREDIMET in einer Übersetzung von Judith Barthel diesmal differenziert geleitet. Ich habe auch auf mich selbst geachtet!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '35', '3', '1023:<p>AHA´s und Gestaltung</p>', '1023:<p>Mit möglichst wenig Eintrag und Aufwand einen pflegeleichten einfachen Garten gestalten. Ich habe mit dem gearbeitet was da war! Kein Schnickschnack oder sehr aufwendige Projekte. Mit den klaren Methoden der Permakultur habe ich einen umsetzbares, schönes und funktionales Design kreiert. Aha\'s: zwei Umsetzungsplanungen: eine zum Diskutieren, eine zum Träumen. Ein erster Entwurf funktioniert super als Diskussionsgrundlage.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '36', '0', '1023:<p><strong>Prozessmodell</strong></p>', '1023:<p><strong>Phasen und <em>Anwendungsmöglichkeiten</em></strong></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '37', '1', '1023:<p>BADUZ</p>', '1023:<p>Beobachten – Analyse – Design – Umsetzung - Zelebrieren</p>\n\n<p><em>Unbegrenzt, auch gut für Mini-Designs</em></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '38', '2', '1023:<p>OVBREDIMET</p>', '1023:<p>- englische Version -</p>\n\n<p>Observation * Vision * Boundaries and Resources * Recording of Site <em>* </em>Examination and Analysis * Design Strategies Chosen * Implementation Strategy <em>* </em>Maintenance Requirements <em>* </em>Evaluation of Results * Tweaking for Improvement</p>\n\n<p><em>Optimal im grünen Permakultur-Bereich</em></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '39', '3', '1023:<p>DesignWeb<sup class=\"footnote\">1</sup></p>', '1023:<p>Wachstumsphase – Entdeckungsphase – Produktionsphase - Reflexionsphase</p>\n\n<p><em>Geeignet für große Projektideen, soziale Designs und Gemeinschaftsprojekte. Eher intuitives Prozessmodell</em></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '40', '0', '1023:<p><em>ALT....</em></p>', '1023:<p>....NEU</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1834', '44', '0', '1023:<p>1. Jahr</p>', '1023:<ul>\n	<li>Sonnenblume pflanzen = Standortthese prüfen</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1834', '45', '1', '1023:<p>2. Jahr</p>', '1023:<ul>\n	<li>Biokompost an der Pflanzstelle vergraben.</li>\n	<li>Im Herbst Stecklinge für die Obstbaumgilde schneiden, z.B. Johannisbeeren, Muskatellersalbei oder Fette Henne.</li>\n	<li>Recherche zu regionale, evtl. seltenen alten Obstbaumsorten.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1834', '46', '2', '1023:<p>3. Jahr</p>', '1023:<ul>\n	<li>Im Frühjahr die Baumscheibe von Gras befreien und eine Gründüngung als Vorbereitung anlegen.</li>\n	<li>Baumschule des Vertrauens finden. Im Herbst den Baum wurzelnackt einpflanzen und die Obstbaumgilde anlegen.</li>\n	<li>Mulchen und freuen!</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1868', '50', '0', '1023:<p>Viele Spaziergänger auf dem Gelände:</p>', '1023:<p>Verkaufs- und Infostand etablieren.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1868', '51', '1', '1023:<p>Problemstandort, trocken und sandig:</p>', '1023:<p>Spargel- und Wildbienen-Paradies!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1868', '52', '2', '1023:<p>Zuviele Gartengeräte:</p>', '1023:<p>sozial wertvolle Ausleih-Netzwerk für Nachbarn aufbauen.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '54', '0', '1023:<p>NO</p>', '1023:<p>Eine Frage taucht auf, ich wundere mich: Warum habe die Tomatenblätter weiße Stellen?</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '55', '1', '1023:<p>O</p>', '1023:<p>Beobachten: der Bedingungen. Ich schmiede einen Plan!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '56', '2', '1023:<p>SO</p>', '1023:<p>Motivation zur Veränderung, neugierig bleiben mit Mut zum Experiment.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '57', '3', '1023:<p>S</p>', '1023:<p>Ich schneide schweren Herzens alle befallenen Blätter ab und bringe die Blätter weg. Ich recherchiere: Was kann ich lernen? Was wissen andere darüber?</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '58', '4', '1023:<p>SW</p>', '1023:<p>Verkörpern. Das Wissen um Pilzerkrankungen und ihre Häufigkeit sacken lassen. Ich über lege im Tagtraum, eine Jauche zur Pflanzenstärkung anzusetzen und mit Ackerschachtelhalmbrühe zu behandeln.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '59', '5', '1023:<p>W</p>', '1023:<p>Am Gartenzaun abends unterhalte ich mich mit den Nachbarn und teiel mein gesammeltes Wissen. Acuh sei kenenn die Pilzsory - un dwissen zu berichten, dass es im großen Zyklus mit den Bodegegebenheiten maßgeblich zu sammenhängt.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '60', '6', '1023:<p>NW</p>', '1023:<p>Ich laufe nochmal zum Gewächshaus zurück und Reflektiere meine AHA-Erlebnisse: Die Wurzel des Probelems liegt im Boden, und feuchte Luftbedingungenverstärken die günstigen Bedingungen für den Pilz.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1951', '61', '7', '1023:<p>N</p>', '1023:<p>Das große Ganze: Ich verknüpfe meine Erkenntnisse mit Erfahrung. Hier beginnt der Kreis ernet mit der Lernfrage: Wie kann ich mich um den Boden kümmern?</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2067', '62', '0', '1023:<p>Aktives zuhören</p>', '1023:<p>Mit dem Bewusstsein des Vier-Ohren-Modells<sup class=\"footnote\">1</sup>. Manchmal genügt es, einfach nur zuzuhören ohne sofort darauf reagieren zu müssen. Ein schönes Beispiel dafür ist ein Redekreis<sup class=\"footnote\">2</sup>, der viele Funktionen vereint und Tiefe in der Zwischenmenschlichkeit schaffen kann. Eine wertschätzende Gesprächsführung ist ein wichtiger Teil von Inklusion!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2067', '63', '1', '1023:<p>Konsens-Prinzip</p>', '1023:<p>Echtes Zuhören, klar Äußern und Anwenden. Systemisches Schnell-Konsensieren für alltägliche Situationen, beispielsweise die Abendplanung!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2067', '64', '2', '1023:<p>Verantwortung für mich übernehmen</p>', '1023:<p>Mithilfe der Bedürfnissprache. Das bedeutet nicht, mein Bedürfnis bei jemandem abladen, sondern mit Klarheit zu äußern: „ich bin müde, hungrig, durstig,…“. Für mich selbst Verantwortung zu übernehmen und sorgen zu können, um dann auch für meine Umgebung sorgen zu können.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2086', '65', '0', '1023:<p>Randzonen sind Potenziale:</p>', '1023:<p>Ampel, Pause, nach dem Weg fragen, Spazieren gehen, Begegnung auf der Toilette.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2086', '66', '1', '1023:<p>Flexible Strukturräume:</p>', '1023:<p>Veranstaltungen oder Meetings plane ich oft zyklisch mit den acht Schilden. Das fühlt sich kongruent und schön an. Probier es auch aus!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2086', '67', '2', '1023:<p>Non-Verbale Gestaltung:</p>', '1023:<p>Geht über Worte hinaus und beeinflusst das Verhalten oft stärker als Regeln, mit Farben, Formen oder Sitzordnungen.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '71', '6', '1023:<p>Mehrjähriges Essen</p>', '1023:<p>Dauergemüse-Beet mit Naschhecke, Obstbaumgilde, Pilzbeet</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '72', '5', '1023:<p>Schönheit&amp; Vielfalt</p>', '1023:<p>Sonnefalle, Pergola, Küchenbauerngarten, Duftgarten, Hausapothekengarten</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '73', '0', '1023:<p>Struktur</p>', '1023:<p>Mikroklima mit Hügel und Senken schaffen (z.B. Swales), Hochbeete, Unterschiedliche Pflanzehöhen mit Leitstauden und -gehölzen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '74', '1', '1023:<p>Platzangebot nutzen</p>', '1023:<p>Waldgarten, Tiny Forest, Naturbadeteich</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '75', '2', '1023:<p>Bodenfruchtbarkeit</p>', '1023:<p>Wurmkompost, Komposttoilette, Gründüngung</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '76', '3', '1023:<p>Kreislaufelemente</p>', '');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2099', '77', '4', '1023:<p>Beetformen</p>', '1023:<p>Hügelbeet, Ziegelhochbeet, Schlüssellochbeet</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '78', '0', '1023:<p>Was?</p>', '1023:<p>Design einer solidarischen Landwirtschaft auf 1,5 Hektar mit einem intensiven Market Garden, Kreisplatz und Agroforst.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '79', '1', '1023:<p>Ziel</p>', '1023:<p>Kollektive Selbstversorgung fördern, miteinander tätig sein zu leben und eine reale Alternative zum Kapitalismus schaffen, möglichst Tauschlogik-frei.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '80', '2', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>BADUZ</p>\n\n<p>Fair share</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '81', '3', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Ein ganzes Design Wochenende organisiert mit allen Beteiligten, um gemeinsam ein Design für den Acker zu entwerfen. Schritt für Schritt sind wir durch den Prozess gegangen, was auch beinhaltet die Bedürfnisse und Begrenzung der Gruppe zu finden.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '82', '4', '1023:<p>AHA´s und Gestaltung</p>', '1023:<p>Das Ressourcen Brainstorming war hat sich gegenseitig potenziert. Am Ende des Designums hatten wir ein klares Konzept und klare weitere Zuordnung der weiteren Planung und AGs im Team. Und besonders viel Spaß bei der Maximalplanung für Wühlmäuse.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '83', '5', '1023:<p>Fazit</p>', '1023:<p>Fazit ein schöner und intensiver Prozess bei dem ich gefühlt in zwei Wochen so viel über Permakultur Design gelernt und gelebt habe wie in einem Jahr. Das war mein erstes größeres Projekt aus dem Permakultur Basisjahr 2020.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '84', '0', '1023:<p>Was?</p>', '1023:<p>Vorgartengestaltung Nützlingsbiotope</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '85', '1', '1023:<p>Ziel</p>', '1023:<p>Permakultur-Blitzaktion als Projektgruppe umzusetzen, etwas Dauerhaftes anzulegen und die Artenvielfalt zu unterstützen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '86', '2', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>BADUZ</p>\n\n<p>Ethischer Schwerpunkt: sozial. Bereits die Umsetzung war stark Gruppenprägend, ein geeminsames Herzensprojekt umzusetzen. Zusätzlich sollen Nachbarn inspiriert werden!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '87', '3', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Ich vor allem planerisch. Habe immer wieder ganzheitlich versucht, die Parteien und Ansprüche unter einen im Kontext sinnvollen Hut zu bringen und „etwas draus zu machen“. Vor allem die Aufarbeitung und Projektdokumentation im Nachhinein bringt mir sehr viel. Wunderbar unterstützt hat mich das Prozessmodell BADUZ mit den klaren Anhaltspunkten.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '88', '4', '1023:<p>AHA´s und Gestaltung</p>', '1023:<ul>\n	<li>\n	<p>Klar fragen: gibt es noch Unklarheiten? Was ist der Nordstern?</p>\n	</li>\n	<li>\n	<p>Heimische Stauden und ihre Ansprüche</p>\n	</li>\n	<li>\n	<p>Wie baue ich ein Up-Cycling Insektenhotel</p>\n	</li>\n	<li>\n	<p>Koordination der Umsetzung von bis zu 10 Menschen. Das Gespür für eine Pause.</p>\n	</li>\n	<li>\n	<p>Beim Zeichnen: Klare Anforderung an den Plan, für wen, welche Zeit und was genau soll wie abstrakt dargestellt werden? Immer einnorden zur besseren Übersichtlichkeit.</p>\n	</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '89', '0', '1023:<p>Was?</p>', '1023:<p>Ein ewiges Gartenhandbuch für das ToGenJi-Projekt. https://www.permakultur.de/ort/togenji-projekt/</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '90', '1', '1023:<p>Ziel</p>', '1023:<p>Ein einfaches Tool für die Planung der Arbeit im Intensiven Selbstversorger-Gemüsegarten des ToGenJi´s. <em>Für Wen:</em> hauptsächlich für Bufdis, Praktikanten und Gäste die länger bleiben. <em>Hauptqualitäten:</em> einfach, praktikabel, anschaulich</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '91', '2', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>5D-RF-Verfahren</p>\n\n<p>Schwerpunkt: Sorge für die Erde</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '92', '3', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Einbeziehen der aktuellen Nutzer und neuen Erfahrungen sowie schon vorhandenen Tools, Entwicklung des Produktidee aus einer offenen Evaluationsrunde. Ich merke immer mehr, wie meine Qualität des „Sichtbar machens“ mehr und mehr Gestalt annimmt und schneller, flüssiger, besser wird! Dass meine Fotos der letzten 3 Jahre hier eingeflossen sind (inkl. Essensbilder) empfinde ich als Ganzheitlich.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '93', '4', '1023:<p>AHA´s und Gestaltung</p>', '1023:<ul>\n	<li>\n	<p>Ich arbeite gerne und viel mit Listen, Tabelle. Ich strebe nach Übersichtlichkeit!</p>\n	</li>\n	<li>\n	<p>Übersichtlicher Garten 2021, 2022 geführt und dann schnelle verwilderung: Das System braucht Pflege. Und einen Notfallplan 😊</p>\n	</li>\n	<li>\n	<p>Schöne Zusammenarbeit mit anderen: sie machen etwas aus der Basis, es entwickelt sich!!!!</p>\n	</li>\n	<li>\n	<p>Wichtig: Andere mit ins Boot holen, das initiale „Evaluationstreffen“ mit offenem Ausgang war Samen legen: Es gibt konkrete weitere Projekte und Ideen zur weiteren Verstetigung vom ToGenJi-Projekt (mehrere mögliche Ziele und eine Sukzessionsplanung von Ideen). Klare Rollenverteilungen, einige klare nächste Schritte.</p>\n	</li>\n	<li>\n	<p>Für mich lang ersehntes „rund machen“ der Zeit hier, weil jetzt klare Rolle als „GarteberaterIn“ (kann kontaktiert werden und frage aktiv nach, wenn ich vor Ort bin). <em>(EDIT: Das wird gerade nicht benötigt, ich stehe zur Verfügung)</em> Zudem erstelle ich weiter die Gemüsegartenplanungen auf Basis der Matrix die ich entwickelt habe. Krönung und damit auch diese Dokumentation: Das Gartenbooklet</p>\n	</li>\n	<li>\n	<p>Zonierung in Kombi mit SWOC-Analyse und Ökosystemkriterien an geeigneter Stelle anwenden</p>\n	</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '94', '0', '1023:<p>1. Beobachte und interagiere</p>', '1023:<ul>\n	<li>Prinzip bei der Standortwahl von Pflanzen anwenden,</li>\n	<li>Nachbarn helfen.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '95', '1', '1023:<p>2. Sammle und speichere Energie</p>', '1023:<ul>\n	<li>Regenwasser leicht erhöht auffangen zur passiven Bewässerung nutzen,</li>\n	<li>Aufschreiben von motivierenden Gedanken.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '96', '2', '1023:<p>3. Erziele eine Ernte</p>', '1023:<ul>\n	<li>Nahrungsmittel,</li>\n	<li>Naturbeobachtung,</li>\n	<li>Wissensaustausch.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '97', '3', '1023:<p>4. Lass die Natur regulieren und lerne aus Feedback</p>', '1023:<p>Ökosysteme regulieren sich selbst und sind sehr produktiv. Bewährt ist, den biologischen Pflanzenschutz durch Mischkultur und Nützlinge zu fördern.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '98', '4', '1023:<p>5. Nutze und schätze erneuerbare Ressourcen und Dienstleistungen</p>', '1023:<ul>\n	<li>Handarbeit,</li>\n	<li>Wind und Sonne, Erdwärme,</li>\n	<li>Regenwürmer als Mitgärtner und Bodenaufbauer unterstützen.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '99', '5', '1023:<p>6. Erzeuge keinen Abfall</p>', '1023:<p>= Kreislaufwirtschaft! z.B. Cradle2Cradle, Strohballen- und Lehmbau, IDGś</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '100', '6', '1023:<p>7. Gestalte vom Muster zum Detail</p>', '1023:<p>Grundstruktur planen, dann den konkreten Inhalt.</p>\n\n<ul>\n	<li>Muster: Wo ist die Betreuung des intensiven Nutzgartens einfach und wieviel Beetfläche brauche ich?</li>\n	<li>Detail: Beetaufbau und Pflanzen</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '101', '7', '1023:<p>8. Integriere mehr, als Du trennst</p>', '1023:<ul>\n	<li>Eine Laube kann genutzt werden zum Aufbewahren, Dachflächenwasser sammeln und Anbau an der Südseite.</li>\n	<li>Im sozialen Bereich ist es wichtig, barrierearm und integrativ zu gestalten.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '102', '8', '1023:<p>9. Nutze kleine und langsame Lösungen</p>', '1023:<p>Alles braucht seine Zeit und gesundes Wachstum auch! Mit kleinen Veränderungen können wir den Überblick behalten, Funktionsweisen begreifen und Schäden verhindern. Z.b.</p>\n\n<ul>\n	<li>langsames Gestalten des Gartens in Jahresetappen, zuerst Gehölze und ein paar Dauergemüsebeete anlegen. Danach Baumscheiben, Gemüsebeete und ein Kompostsystem etablieren.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '103', '9', '1023:<p>10. Nutze und schätze Vielfalt</p>', '1023:<p>Essbare Landschaften sind reizvoll, weil die Diversität übers Jahr auf dem Teller einladend ist und die Gestaltung oft dem 7-schichtigen Waldgartenprinzip folgt.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '104', '10', '1023:<p>11. Nutze Randzonen, und schätze das Marginale</p>', '1023:<p>Artenreiche Säume schaffen, wie:</p>\n\n<ul>\n	<li>Gewässerränder,</li>\n	<li>Mauerkronen und-füße gestalten,</li>\n	<li>Beetbegrenzung als Nützlingsaufenthaltsorte.</li>\n	<li>Und Randzonen wie den Wegesrand als Naschsäume nutzen! :)</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '105', '11', '1023:<p>12. Reagiere kreativ auf Veränderungen</p>', '1023:<p>In der Veränderung die Chance auf Verbesserung sehen:</p>\n\n<ul>\n	<li>Klimawandel = Pflanzenwandel, spezielle Nischen.</li>\n	<li>Oder ein umgestürzter, alter Obstbaum wird zum absoluten Highlight-Habitat im Garten.</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '106', '1', '1023:<p><em>Ich verstehe die Welt nicht...</em></p>', '1023:<p>...Bedingungen und Wechselbeziehungen neu begreifen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '107', '2', '1023:<p><em>Überforderung...</em></p>', '1023:<p>...natürlich Zusammenhänge begreifen und den Blick für die kleinen Wunder der Welt schärfen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '108', '3', '1023:<p><em>Wo fange ich an, was kann ich tun?....</em></p>', '1023:<p>....spielerisch Ideen generieren und klare nächste Schritte verfolgen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2221', '116', '0', '1023:<p>Zone 1</p>', '1023:<p>Haus, unmittelberer Außenraum des Hauses, Wohnung, Quartier</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2221', '117', '1', '1023:<p>Zone 2</p>', '1023:<p>Intensive Pflege: Küchengarten und intensive Gemüsekulturen, Baumschule, Tiere, Intensiv-Kompost</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2221', '118', '2', '1023:<p>Zone 3</p>', '1023:<p>Weniger intensive Pflege: extensiver Gemüsegarten, Gewächshaus</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2221', '119', '3', '1023:<p>Zone 4</p>', '1023:<p>Gelegentliche Pflege: Landwirtschaft, Obst &amp; Nussbäume, Hecke</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2221', '120', '4', '1023:<p>Zone 5</p>', '1023:<p>Naturzone: Wildnis, Ruheraum für die Natur</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2222', '121', '0', '1023:<p><strong>1. Ressourcen:</strong></p>', '1023:<p>Bereitschaft, ein fester Tag in der Woche, gemeinsame Mahlzeiten, Redegegenstand, gemeinsame Pausen.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2222', '122', '1', '1023:<p><strong>2. </strong><strong>Bedürfnisse: </strong></p>', '1023:<p><strong>„</strong>gesehen werden“, privater Austausch (wie geht es mir gerade &amp; was bewegt mich), Klarheit in der Entscheidungsfindung: z.B. Konsens oder Soziokratie.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2222', '123', '2', '1023:<p><strong>3. Begrenzungen: </strong></p>', '1023:<p>maximal eine gemeinsame ruhige Stunde, mögliche Konflikte die mehr Raum brauchen., schlechte Raumverhältnisse: nicht alle sehen sich gut.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '126', '0', '1023:<p>Himmelsrichtung</p>', '1023:<p>Jahreszyklus *** Tageszyklus *** Pflanzenzyklus</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '127', '1', '1023:<p>Nordosten</p>', '1023:<p>1.2. Schneeschmelze *** 3 Uhr morgens *** Der Same keimt</p>');
