INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '129', '3', '1023:<p>Südosten</p>', '1023:<p>1.5. Frühsommer *** 9 Uhr Vormittag *** Wachstum zu üppigem Blattwerk</p>');
