INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2223', '135', '0', '1023:<p>PRODUZIERE KEINEN ABFALL:</p>', '1023:<ul>\n	<li>kompostieren (Wurmkompost),</li>\n	<li>Marmeladenreste als Dressing verwenden,</li>\n	<li>ZeroWaste-Kniffe wie ZwiebelschalenSalz herstellen (köstlich!),</li>\n	<li>Utensilien pflegen</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2223', '136', '1', '1023:<p>INTEGRIERE STATT ZU TRENNEN:</p>', '1023:<ul>\n	<li>Upcycling (z.B. 1. Kartoffelstampf, 2. Scherennudeln),</li>\n	<li>Geschmackskicks (z.B. geschmorte Sellerieknolle raspeln),</li>\n	<li>Wildpflanzen integrieren (z.B. Deko, intensives Pesto zur Abrundung des Essens),</li>\n	<li>gemeinsam kochen</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2223', '137', '2', '1023:<p>KLEINE UND LANGSAME LÖSUNGEN:</p>', '1023:<ul>\n	<li>Ferment-Experimente mit Gemüse-Resten,</li>\n	<li>Zutaten regionalisieren (z.B. Schlehe als falsche Olive),</li>\n	<li>alte Energiespartricks (Kartoffeln in einer Wärmekiste nachdämpfen lassen),</li>\n	<li>Konsumpyramide beachten</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '138', '0', '1023:<h6>Wünsche</h6>', '1023:<h6>Individuelle Gestaltung</h6>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '139', '1', '1023:<p><em>\"Ich habe zwei Stunden Zeit pro Woche und möchte hauptsächlich frisch ernten und kochen.\"</em></p>', '1023:<p>Statt eines intensiven Gemüsebeets habe ich mich für drei Obstbäume mit Kräuterbaumscheiben und Dauergemüsebeete entschieden. Meine persönlichen Highlights: Salat mit essbaren Blüten&amp; Wildkräutern und die Apfelernte im Herbst!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '140', '2', '1023:<p><em>\"Ich wünsche mir einen harmonischen Ziergarten der auch nutzbar ist und mich erfreut!\"</em></p>', '1023:<p>Meine Bauerngarten-Stauden-Rabatte sind ergänzt mit Dauergemüse wie Mangold der schön für Insekten blüht. Unterschiedlichste Blüten setzen die einzelnen Gartenplätze übers ganze Jahr verteilt in Szene und sind Insektenmagnete! In einem eher sonnigen und mageren Beet habe ich heimische Magerpflanzen kombiniert mit Holzkunst-Elementen die sich nach und nach zersetzen und Heimat werden für unzählige kleine, nützliche Garten-Mitbewohner</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '141', '3', '1023:<p><em>\"Der Garten soll für meine Familie ein Ort der Ruhe, des Spielens und Lernens mit der Natur sein.\"</em></p>', '1023:<p>Wir haben einen Grillplatz mit offenem Pflaster, Mini-bete für die Kinder, Erdbeer-naschsäume an den Wegen und Verstecke, wie der Weidentunnel. Immer parat: Lupe, Bücher und eine Pflanzenpresse.</p>');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('27', '<p>Die gesuchte Seite wurde nicht gefunden.<br />Zurück zur <a	data-pwid=1	href=\"/\">Startseite</a>.</p>', NULL);
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1109', '<p>Um zukunftsfähige Lebensräume resilient und bunt zu gestalten, orientiert sich die Permakultur an natürlichen Ökosystemen. Mit ethischen Prinzipien und systemischem Denken, verweben sich strukturierte Methoden zu einzigartigen und lebendigen Designs.</p>\n\n<p>Herzlich willkommen in meiner herrlichen Permakultur-Welt. Caro</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1168', '<p>Wie komme ich von der Idee zu einer Lösungsstrategie?</p>\n\n<p>Mit Hilfe von Projektmanagement-Tools, natürlichen Mustern und anderen „Werkzeugen“ kommen wir Schritt für Schritt, zu realistischen, zukunftsfähigen Gestaltungen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1171', '<p>Eine ganzheitliche Gestaltung ist systemisch, vernetzt und bildet sich auf Basis der Permakultur-Ethik. Nach dem Vorbild der Natur entfalten sich stabile, dynamische und gesunde Biotope für alle Menschen, Tiere, Pflanzen, Mikroorganismen, Insekten und Pilze.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1175', '<p>Die Permakultur orientiert sich an den natürlichen Kreisläufen, als fester Bestandteil von Ökosystemen. Die wiederkehrende Muster führen zu Resilienz, Integration und Entwicklung. Wenn wir das zyklische Denken tief verstehen und danach gestalten, entstehen ganzheitliche, harmonische Designs.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1178', '<p>Permakultur zu leben, drückt sich bunt und subtil im Alltag aus. In den kleinen, alltäglichen Entscheidungen und Lösungswegen spiegelt sich die Ethik wieder. Konkrete Gestaltungen für Bereiche des Alltags können viel Spaß und Sinn machen! Langsam und behutsam wächst so von Innen nach Außen, dein eigenes resilientes System.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1181', '<p>Soziale Permakultur: beschreibt eine Gestaltung, die auf mehreren sozialen Ebenen durchdacht ist. So schaffen wir die Bedingungen und die Umsetzung von: Innen- und Außenräumen, Prozessen und gutem, gelebtem Miteinander. Wie kann ich authentisch mein Leben führen? Welche Zutaten braucht ein herrlicher Lagerfeuerabend? Und wie gestalte ich in Projekten einen konstruktiven, wertschätzenden Umgang mit Konflikten?</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1184', '<p>Oder auch präziser die „landbasierte Permakultur“, ist eine resiliente Gestaltung von Landflächen mit Strukturen, Pflanzen &amp; Elementen nach dem Vorbild der Natur. So entstehen kreislaufbasierte, essbare und artenreiche Paradiese.</p>\n\n<p>Mögliche Flächen für eine Permakultur-Gestaltung sind: Balkon, Nutz- und Ziergehölze, Parks, Landwirtschaftliche Fläche, wie Äcker oder SoLAWiś.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1187', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1244', '<ul>\n	<li>Permakultur orientiert sich an der Natur und hilft, nachhaltige und lebensfreundliche Systeme zu gestalten.</li>\n	<li>\n	<p>Wichtige Grundlage sind drei Ethiken: Sorge für die Erde, Sorge für die Menschen und gerechtes Teilen.</p>\n	</li>\n	<li>\n	<p>Einfache Schritte helfen beim Gestalten: beobachten, verstehen, planen und dann bewusst handeln.</p>\n	</li>\n</ul>\n\n<p>Permakultur (leben) bedeutet für mich: <strong>Mit einem ethisch verwurzelten Gefühl planen, handeln und lächeln.</strong></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1317', '<p>Du hast ein Problem? Permakultur bietet ganzheitliche Lösungen! Komm in zu mir in die Online-Sprechstunde mit deiner Frage. Wir beginnen die Sprechstunde im redekreis, um anzukommen und in den tiefen Austausch zu finden. Im Anschluss gibt es die offene Fragerunde an mich, schick mir gerne mit dem Anmeldeformular eine konkrete Frage. So kann ich bestmöglichst helfen. Wenn wir noch Zeit haben, gebe ich Euch gerne einen Mini-Input zur Inspiration. <br /><br />\n🧭 Art<br />\nonline / 1x im Monat / inspiriered<br /><br />\n⚙️ Ablauf<br />\n- 30 min Redekreise<br />\n- 45 min Fragerunde (max. 10 Fragen)<br />\n- evtl. Zeit zum Austausch oder Mini-Input <br /><br />\n 💎 Rahmen<br />\nmax. 15 Tickets pro Sprechstunde / 15 Euro / 1,5h</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1320', '<p>Ich begleite Menschen, Gruppen und Projekte in einem gemeinsamen Gestaltungsprozess. Dabei verbinde ich ökologische, soziale und zyklische Perspektiven zu einem stimmigen, kontextbezogenen Permakultur-Design.</p>\n\n<h6>Diese Beratung eignet sich besonders für:</h6>\n\n<ul>\n	<li>\n	<p>naturnahe Gärten und essbare Landschaften</p>\n	</li>\n	<li>\n	<p>Leuchtturmprojekte (z. B. solidarische Landwirtschaft, Transition Towns, Heckenretter)</p>\n	</li>\n	<li>\n	<p>Gemeinschaften, Initiativen und Bildungsorte</p>\n	</li>\n	<li>\n	<p>öffentliche Räume und kooperative Projekte im urbanen und dörflichen Kontext</p>\n	</li>\n</ul>\n\n<p>Gemeinsam entwickeln wir ein Design, das ökologisch tragfähig, sozial lebendig und langfristig resilient ist. Auf Wunsch halte ich die Ergebnisse in Skizzen, Plänen, Pflanzlisten oder einem Leitfaden fest.</p>\n\n<h6>Ich biete dir / euch:</h6>\n\n<ul>\n	<li>\n	<p>sorgfältige Vorbereitung und achtsame Begleitung</p>\n	</li>\n	<li>\n	<p>einen individuellen Permakultur-Workshop vor Ort</p>\n	</li>\n	<li>\n	<p>Prozess- und Gruppenbegleitung (z. B. mit Elementen aus Dragon Dreaming)</p>\n	</li>\n	<li>\n	<p>3 Tickets für die Permakultur-Sprechstunde als Geschenk</p>\n	</li>\n</ul>\n\n<h6>Ablauf</h6>\n\n<ul>\n	<li>\n	<p>Erstkontakt &amp; Fragebogen</p>\n	</li>\n	<li>\n	<p>Vorbereitungsgespräch online</p>\n	</li>\n	<li>\n	<p>Beratung &amp; Workshop vor Ort</p>\n	</li>\n	<li>\n	<p>Nachbereitung, ggf. Anschlussberatungen</p>\n	</li>\n</ul>\n\n<h6>Rahmen</h6>\n\n<ul>\n	<li>\n	<p>individuell</p>\n	</li>\n	<li>\n	<p>🔁 80 € pro Stunde</p>\n	</li>\n	<li>\n	<p>zzgl. bezahlte An- und Abreise</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1327', '<p>🧭 Du suchst<br />\n- individuelle Impulse und Lösungansätze für deinen Garten, Projekt und andere Lebensräume<br />\n- eine klare einstündige Beratungen<br />\n- plus weiterführendes Material und Vorschläge für nächste Schritte<br /><br />\n⚙️ Ablauf<br />\n- ich sende Dir einen detaillierten Fragebogen, damit ich mir einen Überblick über deine Situation, Gegebenheiten und Fragen bekomme. Wir vereinbaren einen Termin zur online Erstberatung.<br />\n- persönliches 1h online Beratungsgespräch plus Ticket zu einer Permakultur-Sprechstunde<br />\n- weiterführende Informationen und Impulse <br /><br />\n 💎 Rahmen<br />\n 1h persönliche Beratung / 150 Euro / inkl. Ticket zur Permakultur-Sprechstunde</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1328', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1330', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1331', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1386', '<p>Ein System zu erfassen, zu analysieren und perspektivisch für ca. 150 Jahre<sup class=\"footnote\">1</sup> zu designen, ist komplex, aber nicht unbedingt kompliziert.<br />\n„Und wie fange ich an?“<br />\nMit dem ethischen Kompass und Motivation einfach loszulegen, ist eine wirkungsvolle Grundlage - und reicht alleine nicht aus. Wenn wir naturnahe Systeme imaginieren und entwerfen, ist es sinnvoll ein Grundgerüst, sozusagen einen Fahrplan, zu haben. Dazu gibt es passende Prozessmodelle, entlehnt aus dem Projektmanagement, die uns einen Leitfaden bieten und so beim Gestalten unterstützen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1392', '<p>Die Permakultur-Methodik benutzt verschiedene Prinzipien als sinnvolle Ankerpunkte und ganze Prinzipien-Sets als Gestaltungs- und Reflexions-Hilfe. Es sind viele kleine Fingerzeige und Grundmuster die uns lebendige Facetten von natürlichen Systemen aufzeigen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1398', '<p>Alle Prozessmodelle haben eine logische Abfolge, die entweder intuitiv genutzt oder relativ fest - Phase für Phase - durchlaufen werden können.</p>\n\n<p>In ihrer Abfolge sind die Prozessmodelle zyklische, und teilweise kreative Leitfäden für eine Gestaltung. Manche sind kurz, andere kleinteilig und wiederum andere sehr offen, lebendig vernetzt und fraktal.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1404', '<p>Das Beobachten als Grundlage hat mein Leben verändert, bringt mir Freude, Zufriedenheit und Entschleunigung.</p>\n\n<p>Ich liebe es, mit einer Tasse durch den Garten zu streifen, natürlich zu lernen und einfach mit den Gegebenheiten in Verbindung zu sein.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1410', '<p>Eine gründliche Analyse des beobachteten Systems, seiner Elemente und Aspekte ist richtungsweisend für eine Planung. In meinem Design-Alltag nimmt die Analyse – oft zu Recht – den meisten Raum ein. Auch wenn ich darauf abziele, alle Phasen im Prozess zeitlich relativ ausgewogen zu durchfließen.</p>\n\n<p><em>Analyse heißt:</em></p>\n\n<p>Grund rein bekommen. Rechtliche Klarheit, Bedürfnisse und Probleme benennen, Chancenfenster erkennen, Knackpunkte herausfiltern.</p>\n\n<p>Das bedeutet insgesamt: in Kontakt gehen und ein tiefes Verständnis entwickeln.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1416', '<p>Permakultur-Gestaltung, oder auch Permakultur-Design, zielt hin zu einer bewussten Gestaltung auf Basis von Ethik, Prinzipien und Mustern.</p>\n\n<p>Zu diesem Zeitpunkt  haben wir zu den Projektgegebenheiten auf systemischer Ebene schon intensiv Kontakt aufgenommen. Durch die vorrangegangene Beobachtungs- und Analyse-Phase sind bereits möglichst viele unterschiedliche Ecken, Ebenen und Zusammenhänge beleuchtet. Nun, in der Gestaltungsphase, kommt alles zusammen, ergibt Sinn und wird weiter gedacht.</p>\n\n<p>Konventionelle Gestaltungen bilden eine eingefrorene Aufnahme der Wirklichkeit ab, z.B. wie der Garten zu einem einzigen Zeitpunkt in 10 Jahren aussehen wird. Permakultur macht hier die Nischen sichtbar und nutzt sie. Wie entwickelt sich das System innerhalb von 10 Jahren? Kann ich alle Zeiträume mit kleinen &amp; langsamen Lösungen effektiv nutzen? Und was kommt danach, in 25 oder 50 Jahren?</p>\n\n<p>Ich arbeite gerne mit Overlays, die Bedingungen sichtbar machen, wie Sichtachsen oder auch notwendige Materialflüsse.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1422', '<p>Umsetzen bedeutet: in die Realität bringen, ganzheitlich Handeln und oft auch experimentieren! In der Permakultur erfüllt ein Element oft mehrere Funktionen. Kann der Bau einer Komposttoilette nicht nur meinen Nährstoffkreislauf schließen. Für die Umsetzung lade ich andere Menschen zum Bauen ein. Gemeinsam lernen, werkeln und lachen; daraus kann das nächste Projekt oder noch viel mehr entstehen!</p>\n\n<p>Eine logische Abfolge – eine Umsetzungsplanung - hilft uns, die Ressourcen wie finanzielle Mittel oder Materialien im Blick zu haben oder auch passend auf Kleinanzeigen zu stöbern.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1428', '<p>Für ein mehr als nachhaltiges, also regeneratives-fortbestehendes Design, orientieren wir uns an den Mustern, Prozessen und Lösungen der Natur. Seit Urzeiten feilen die Energie- und Elementeflüsse an der Erdstruktur, und das Leben entwickelt Muster und Fähigkeiten, die sich bewährt haben. „Die Natur“ ist wirklich effektiv, kreativ und in individuellen Fraktalen wunderschön.</p>\n\n<p>Hier ein paar Beispiele für solch wirklich cleveres Design und Ideen der menschlichen Imitation:</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1434', '<p>Was genau heißt „langfristig“? Die Permakultur hat eine Idee dazu aufgegriffen: \"langfristiges Denken\" ist ein Zeitraum von 7 Generationen<sup class=\"footnote\">1</sup>. Das entspricht im Wald-Kontext ca. 500 Jahren, für uns Menschen eher 150 Jahren. Schau dich um und stelle dir vor: Wie wird der Platz, an dem Du gerade bist, in 7 Generationen, also ca.150 Jahren aussehen? Konstant bleiben die chemischen Bestandteile, wie Sauerstoff, Kohlenstoff, Stickstoff und der ganze andere Sternenstaub.</p>\n\n<p>Wir sind alle verbunden - das ist nicht nur ein wahres Gefühl. Wir leben auf demselben Planeten: statistisch waren die Phosphorteile in meinem Körper bereits 8000-mal in einem anderen Organismus verkörpert. Was ändert sich in deinen Gedanken, wenn Dir klar wird: Du teilst diese Benutzung und da kommt noch jemand nach dir auf der Toilette?</p>\n\n<p><strong>Langfristiges Denken</strong></p>\n\n<p>benötigt Gehirnjogging-Fähigkeiten und bildet Vertrauen aus</p>\n\n<p><strong>Konträres akzeptieren</strong></p>\n\n<p>...,denn bei vielen Projekten ist es total unklar, ob diese Bestand haben werden, oder ob die Flächen dauerhaft genutzt werden können.</p>\n\n<p><strong>Plane mit der Klarheit!</strong></p>\n\n<p>Alles ist Veränderung! Das gibt Gelassenheit und die Möglichkeit der Sukzessionplanung.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1440', '<p>Unsere Welt ist skaliert zwischen Polen. Hitze und Kälte, Gesundheit und Krankheit, Schwarz und Weiß. Durch das Fließen zwischen den Gegensätzen können wir überhaupt wahrnehmen, empfinden und einordnen.</p>\n\n<p>Die größte Lebendigkeit finden wir an Übergängen, dem große Muster der Randzonen. Dort, wo die Elemente Wasser, Feuer, Erde, Luft und Liebe aufeinandertreffen. An diesen Knotenpunkten entsteht reger Austausch und Neues, zwischen unterschiedlichen Habitaten. In sogenannten Multi-Habitat-Landschaften<sup class=\"footnote\">1</sup> floriert das Leben und die Diversität, bietet noch mehr Nischen für Lebewesen.</p>\n\n<p><em>Bsp: Waldrandzone, Flussaue, Seeufer.</em></p>\n\n<p>Ein Übergang ist gleich eine Schwelle. Eine Zustandsveränderung im Prozess der Entwicklung kommt manchmal impulshaft, schnell und plötzlich, wenn ein Kippunkt erreicht wird. Oft schleichend und sich ankündigend.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1444', '<ul>\n	<li>\n	<p><strong>Prozessmodelle geben Struktur:</strong> Designprozesse folgen meist klaren, oft zyklischen Phasen (z. B. Beobachten, Analyse, Design, Umsetzung), die helfen, Ideen systematisch zu entwickeln und Entscheidungen zu treffen.</p>\n	</li>\n	<li>\n	<p><strong>Beobachtung und Analyse sind die Grundlage:</strong> Durch bewusstes Beobachten und gründliche Analyse von Systemen, Mustern, Ressourcen und Bedürfnissen entsteht ein tiefes Verständnis für Probleme und Chancen.</p>\n	</li>\n	<li>\n	<p><strong>Design und Umsetzung für nachhaltige Lösungen:</strong> Auf Basis der Erkenntnisse wird ein langfristiges, systemisches Design entwickelt und anschließend praktisch umgesetzt und gepflegt – oft experimentell und mit mehreren Funktionen pro Element.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1451', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1457', '<p>Das 8-Schilde-Modell ist ein systemisches Naturverbindungs- und Bildungsmodell, das von John Young (Wildnispädagogik) entwickelt wurde<sup class=\"footnote\">1</sup>. Es basiert auf den natürlichen Rhythmen und Zyklen der Erde und ist in acht verschiedene Phasen unterteilt, die sich in Himmelsrichtungen wiederspiegeln.</p>\n\n<p>Die Pflanzenzyklen im Jahresverlauf unserer Klimazone zeigen deutlich die verschiedenen Qualitäten, die mit den Himmelsrichtungen verknüpft werden.</p>\n\n<p>Wie eine Pflanze durch diese acht Phasen und jeweiligen Qualitäten durchzulaufen, beginnend im Nordosten und endend im Norden, wurde für mich ein ganzheitlicher und wertvoller Teil meines Lebens. Mit gutem Anfang als Start und einer Reflexion am Ende gestalte ich alltäglich und vor allem im Gruppenkontext zyklische, ganzheitliche Prozesse. Mit allen Aspekten wird Integration möglich für natürliches Wachstum, Nachhaltigkeit und Resilienz auf allen Ebenen (materiell, emotional, sozial).</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1463', '<p>Natürliche Zyklen wiederholen sich, sind aber nie gleich.</p>\n\n<p>Das ermöglicht regeneratives Wachstum, Entwicklung und Reintegration. Wenn ein Apfel entsteht folgt dies der Reihenfolge: Knospe-Blüte-Fruchtknoten-Apfel. Der Apfel wächst mit den Bedingungen, die ihm gegeben sind, seien das Licht, Wasser, Nährstoffe, eine Verletzung der Schale, Würmer, etc… Das Ergebnis, beziehungsweise die Frucht, ergibt sich aus den Umständen. Währenddessen wächst aus dem Neuaustrieb des Apfelbaumes eine frische Knospe, angelegt für das nächste Jahr. So beginnt der Zyklus zeitgleich von vorne.</p>\n\n<p>Im Gegensatz zum Apfelbaum haben wir Menschen die Fähigkeit zur Imitation, Analogien zu sehen und bewusster Reflexion. Als Designerin nutze ich dieses natürliche Potenzial, indem ich mir verschiedener Zyklen bewusst bin und überwiegend innerhalb dieser wiederkehrenden Muster plane. Ich vertraue, denn Zyklen wiederholen sich, sicher.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1469', '<p>In fortwährenden und kontinuierlichen Prozessen entfaltet sich die Tiefe des 8-Schilde-Modells. Dein individuelles Leben hat seinen ganz eigenen Rhythmus, der sich verändert und abhängig ist von deinem Charakter, Vorlieben, physischen Möglichkeiten und deiner Umgebung. Doch vor allem: Von dem, was Du Dir vorstellen kannst!</p>\n\n<p>Jeder Organismus hat seine ureigenen Strategien im Leben, ob Igel, Mensch oder ein Pilzmycelgeflecht. Finde deinen individuellen Rhythmus &amp; Schwung!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1492', '<p>Was sind Probleme? Hindernisse auf dem Weg zum Paradies!</p>\n\n<p>In der anthropozentrisch geprägten Welt ist die Lösung zu oft gewesen, ein Hindernis zu überspringen, beiseite zu räumen oder zu zerstören.</p>\n\n<p>Ich lade Dich ein: Hindernisse zuerst wahrzunehmen und deine Emotionen dazu. Im nächsten Schritt frag ganz offen: Warum ist das Problem da? Welche Bedingungen begünstigen das Hindernis, was passiert, wenn wir es bekämpfen oder vernichten würden? Und könnten wir es auch als Chance begreifen und in ein Design mit einbauen?</p>\n\n<p>Oft zeigen uns die Probleme klare Fakten auf und ermutigen, kreativ nach Chancen und Möglichkeiten zu suchen. Lösungsorientiertes Design beschäftigt sich maximal 40% der Zeit mit den Problemen. Ein riesiges, transformatives Potenzial! Stell Dir vor, alle Menschen würden anfangen, dieses Denkmuster zu kultivieren – der Glücksindex und Friedensfaktor könnten großen Zuwachs verzeichnen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1498', '<p>Systemisches oder auch vernetztes Denken ist Teil von unserer „Permakultur-Brille“. Das Gegenteil davon wäre ein isolierter Blick auf einzelne Elemente. In lebendigen Systemen hingegen, ist alles miteinander verbunden – Beziehungen, Wechselwirkungen und Kreisläufe verweben sich zu einem großen Bild.</p>\n\n<p>Neulich beim Fastenbrechen nach sieben Tagen, lag ein Apfel und etwas Erdnussbutter vor mir auf dem Teller. Beim ersten, saftigen Biss in den Apfel schloss ich die Augen und vor meinem inneren Auge entstand eine rückwärtslaufende Bilderfolge: die Apfelernte, die Blüte im Frühling, eine bestäubende Biene, der Mensch, der den Baum einst gepflanzt hat. In diesem Moment spürte ich eine tiefe Verbundenheit – unabhängig von Zeit und Raum.</p>\n\n<p>Hat der Baum vor meiner Haustür etwas mit mir zu tun?</p>\n\n<p>Und verändert sich etwas in der Umgebung, wenn er nicht mehr da wäre?</p>\n\n<p>Systemisches Denken lädt uns ein, genau solche Fragen zu stellen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1535', '<p>Das grundlegenste Permakultur-Prinzip ist die Ethik, eine innere, philosophische Annahme die im Kontext angewendet wird. So formt deine persönliche Haltung deine innere, einzigartige Landschaft - mit Auswirkungen auf den Alltag und alle Lebensbereiche.</p>\n\n<p>Innere Landschaften können ebenso „begärtnert“ werden, für ein Leben in Fülle! Schritt für Schritt machst Du dir ein Geschenk: Dich selbst kennen und lieben zu lernen! Wenn Du dich gut kennst und ausdrücken kannst im Außen, fließt es ganz einfach vom Ich zum Wir, von innen nach außen. So schaffst Du sozusagen förderliche Bedingungen.</p>\n\n<p>Die Permakultur-Ethik und unsere Emotionen sind unser innerlicher, natürlicher Kompass für unseren Alltag. Deine Emotionen schütteln dich durch? Betrachte die Probleme als dornige Chancen. <em>Angst</em> – zeigt Dir eine Möglichkeit, sie macht Dich aufmerksam auf etwas, das Du nicht kennst. <em>Wut </em>zeigt Dir einen Umstand, den Du gerne ändern möchtest und gibt Dir Kraft zur Handlung, im Sinne der Ethik.</p>\n\n<blockquote>\n<p>„Achte auf deine Gedanken, denn sie werden zu Worten. Achte auf deine Worte, den sie werden zu Handlungen. Achte auf deine Handlungen, denn sie werden zu Gewohnheiten. Achte auf deine Gewohnheiten, denn sie werden zu deinem Charakter. Achte auf deinen Charakter, denn er wird dein Schicksal.“ - Unbekannt -</p>\n</blockquote>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1541', '<p>Die Gesundheit und Balance in unserem Körpersystem ist ein Prozess, und zugleich wirken viele Einflüsse aus der Umwelt auf uns ein. Das hat nicht nur Auswirkungen auf unsere Zell- und Organgesundheit, sondern wirken beispielsweise Dauerlärm und Informationsflut auch auf unseren Nervenkostüm. Was stärkt deine Resilienz? Wie kannst Du gut und natürlich für Dich sorgen?</p>\n\n<p>Seit vielen Jahren experimentiere ich mit Spaß und suche meine passenden Wege der Selbstfürsorge. Vor allem als als Wertschätzung für diesen Körper, der mich jeden Tag trägt und mit Sinneseindrücken beschenkt. Durch meinen Körper bin ich in Kontakt mit meiner Mitwelt.</p>\n\n<p>Betrachte mal deine Hände: kannst du sehen, was diese Wunderwerkzeuge schon geleistet, gehalten oder gedreht haben? Diese Hände haben viel Weisheit erfahren, dein Erfahrungswissen. Dem kannst Du vertrauen!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1547', '<p>In der Küche zu stehen und zu kochen ist für mich eine Urverbindung. Mit dem Körper, mit dem Garten, mit den Menschen, die die Lebensmittel produziert haben, mit dem Kreislauf. „Die Küche“ ist eines der flexibelsten, wichtigsten Systeme. Hier sind Lebendigkeit, Genuss und viel Lernpotenzial in Fülle vorhanden.</p>\n\n<p>Beim Kochen habe ich gerne die „Permakultur-Brille“ auf der Nase, durch die ich (im übertragenen Sinne) die Dinge betrachte. Ich bemerke, dass es in meiner Küche um viel mehr geht als nur Schnippeln – Zusammenwerfen – Genießen. Es ist, als würde man die Komplexität ohne Permakultur-Brille häufig nicht wahrnehmen. Oder es ist der Vergleich zwischen einem Weihnachtsessen auf einer kleinen Postkarte, im Gegensatz zu einem lebendigen, duftenden Weihnachtsschmaus im Kreise meiner liebsten Menschen.</p>\n\n<h6>Diversität – Vielfalt in der Küche</h6>\n\n<p>Viele unterschiedliche Küchen der Welt und Rezepte setzen auf Diversität in der Einfachheit – oder anders gesagt: süß, sauer, salzig, bitter und umami. Umami bedeutet: schmackhaft, würzig oder auch wohlschmeckend. Seit kurzem experimentiere ich auch mehr in der Komponente der Schärfe. Diese ist keine Geschmacksrichtung, aber beispielsweise kann ein Klecks Kimchi dem Essen Tiefe verleihen. Ich achte in meiner Küche darauf, möglichst alle Geschmacksrichtungen zu vereinen. Genauso kann man mit verschiedensten anderen Kniffen Diversität im Mund erlangen – verschiedene Texturen, Temperaturen und Gewürze. Nach einem mit Liebe zubereiteten Mahl fühlen wir uns ganz rund und wohlig..</p>\n\n<h6>Die 8 Schilde als Leitfaden</h6>\n\n<p>Ich erwähnte eine ganz entscheidende Zutat – die Liebe und Hingabe zu den Geschenken der Erde, unserer fein ausgestatteten Küche, den Gästen die wir erwarten und vielleicht sogar ein Motto oder Thema, das den Abend begleitet. Sei es eine Geburtstagsfeier, Erntedank in der Solidarischen Landwirtschaft, das alltägliche Abendessen mit der Familie oder ein Wochenendkurs zum Thema Lebendige Lebensmittel mit 15 Menschen.</p>\n\n<p>Die 8 Schilde unterstützen uns, diesem Prozess einen Rahmen zu schenken und damit unsere Küche rund und resilient im Inneren (Menschen, Gespräche,…) und Äußerem (Teller, Atmosphäre,…) zu machen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1553', '<p>Der Ort, an dem Du lebst, wohnst und wirkst, ist ein zentraler Raum für Permakultur im Alltag. Unsere Wohnräume sind nicht nur funktionale Orte – sie sind Lebensräume, die gestaltet, gepflegt und bewusst genutzt werden können.</p>\n\n<h6>Heimat suchen</h6>\n\n<p>Nach vielen Umzügen habe ich tief reflektieren dürfen: Was bedeutet Heimat für mich? Anzukommen in jedem Moment, da, wo ich gerade bin und in Kontakt mit den Umständen zu gehen. Aktiv gestalten, was in meinem Möglichkeitsbereich liegt. Was brauche ich wirklich, und was ist mir wichtig? Mein flexibles Leben erinnert mich immer wieder an ein Permakulturprinzip: mit Ressourcen bewusst umgehen. Weniger Besitz kann auch mehr Freiheit bedeuten.</p>\n\n<p><strong>H</strong><strong>eimat gestalten</strong></p>\n\n<p>Permakultur bedeutet, Wohn-Räume zukunftsfähig und klug zu gestalten. Neben der Architektur und grundlegenden Entscheidungen wie Neubau oder ökologisches Sanieren, ist auch die Innenraumgestaltung wichtig. Ein gutes Beispiel ist die Einrichtung eines Wohnzimmers. Hier lässt sich Permakultur-Design sehr anschaulich erklären – denn die wichtigste Regel lautet: <span class=\"highlight\">Es kommt darauf an.</span>Jede Gestaltung entsteht aus den jeweiligen Bedingungen:</p>\n\n<ul>\n	<li>\n	<p>Größe und Schnitt des Raumes</p>\n	</li>\n	<li>\n	<p>Fenster, Türen und Stromanschlüsse</p>\n	</li>\n	<li>\n	<p>persönlicher Geschmack</p>\n	</li>\n	<li>\n	<p>Bedürfnisse im Alltag</p>\n	</li>\n	<li>\n	<p>vorhandene Ressourcen oder Dinge aus zweiter Hand</p>\n	</li>\n</ul>\n\n<p>Braucht der Raum eine Essecke, einen Ort zum Entspannen, eine Spielecke, Platz für Pflanzen oder vielleicht sogar ein kleines Meerschweinchengehege? All diese Fragen gehören zum Designprozess.</p>\n\n<p>Wohnraum kann zudem ein sozialer Raum sein. Oft bleibt er teilweise ungenutzt und kann geteilt werden – etwa in Wohngemeinschaften oder gemeinschaftlichen Projekten. Gemeinsames Wohnen bringt automatisch soziale Prozesse mit sich: Organisation, Kommunikation, gegenseitige Unterstützung und gemeinsames Lernen. So wird Heimat gemeinsam gestaltet.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1559', '<p>Ich liebe es, unterwegs zu sein, es gehört ganz zur menschlichen Natur und unseren zwei Beinen dazu. Neue Perspektiven entdecken, Altes hinter mir lassen. Oft bin ich auf Reisen und kleinen Ausflügen so inspiriert, dass sich mein Notizheft ganz von alleine füllt. Doch die Art und Weise, unterwegs zu sein, hat sich für mich gewandelt.</p>\n\n<h6>Wie groß muss mein Radius sein?</h6>\n\n<p>Im Sinne der Entschleunigung tat es mir für mein Leben gut, meinen Radius zu reflektieren. Klar, seit einigen Jahren habe ich mich bewusst gegen Flugreisen entschieden und für langsames Reisen. Nichtsdestotrotz war ich durchaus viel unterwegs, immer im Handgepäck den „ich könnte etwas verpassen“-Koffer. Ist das Lebendigkeit? Keine einfachen Fragen…</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1565', '<p>Eine menschliche Kultur ist begründet in unserer gemeinsamen Wertebasis und unseren Normen. Sie wird weitergegeben, gepflegt und geprägt. <em><strong>Wir geben dem Bedeutung, dem wir Raum geben.</strong></em></p>\n\n<p>Ich wünsche mir eine wertschätzende, inklusive Kultur mit Fokus auf das, was uns eint. Das größte Potenzial, oder auch Hebel der Transformation, sind meiner Meinung nach \"tiefe Strukturen\", wie zum Beispiel essen, schlafen, singen. Eine neue Kultur bildet sich nicht über Nacht aus, aber immer aus tiefer Überzeugung.</p>\n\n<p>Welche Kultur möchtest Du spüren?</p>\n\n<p><strong>Rhythmischer Alltag</strong></p>\n\n<p>Ich möchte auf mich achten und mich nicht vernutzen. Nach dem Modell der 8 Schilde versuche ich zyklisch zu leben. Was brauche ich im Feld der Entwicklung, zwischen An- und Entspannung?</p>\n\n<p>Mein persönlicher Alltags- und Büro-Rhythmus orientiert sich eher an einem 7-tägigen Rhythmus und, als menstruierende Person, am Monatszyklus. Meine Gartenzeit folgt schon seit Jahren einem 2-wöchigen Rhythmus-Fenster, in dem ich Aussaat, Anzucht, Pflanzen, Pflege- und Düngemaßnahmen plane. Innerhalb von 14 Tagen eine passenden Zeitpunkt und günstige Umstände zu finden, ist für mich eigentlich immer irgendwie möglich.</p>\n\n<p>Ich versuche den Alltag als Fluss zu sehen, nicht abgehakte ToDoś. Das gelebte Leben ist nie ganz fertig, und Prozesse laufen gleichzeitig. Starte wirkungsvoll mit folgenden Inspirationen: große Ziele verfolgen in kleinen Schritten. Minimalismus einladen: Leben nach der 80/20-Regel. Alltag nicht zu einschleifen lassen, regelmäßig Neues ausprobieren. Bleib Neugierig, lass Dich leiten und warte nicht auf morgen.</p>\n\n<p>Dafür ist das Leben zu kurz.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1568', '<ul>\n	<li>\n	<p><strong>Zyklisches und ganzheitliches Denken:</strong> Permakultur orientiert sich an natürlichen Kreisläufen (z. B. Jahreszeiten, Wachstum, Vergehen). Nichts ist statisch – Entwicklung entsteht durch wiederkehrende, aber sich verändernde Zyklen.</p>\n	</li>\n	<li>\n	<p><strong>8-Schilde-Modell als Prozessrahmen:</strong> Das Modell beschreibt acht Phasen eines natürlichen Zyklus (z. B. Impuls, Orientierung, Fokus, Gemeinschaft, Reflexion) und dient als Orientierung für Gestaltung, Lernen und Zusammenarbeit.</p>\n	</li>\n	<li>\n	<p><strong>Prozesse und individueller Rhythmus:</strong> Leben, Lernen und Gestalten sind langfristige Prozesse. Nachhaltige Entwicklung entsteht, wenn wir natürliche Rhythmen respektieren, Geduld haben und unseren eigenen Rhythmus finden.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1572', '<ul>\n	<li>\n	<p><strong>Permakultur beginnt im Alltag und in der inneren Haltung:</strong> Unsere Gedanken, Emotionen und Entscheidungen prägen den Alltag. Mit bewusster Beobachtung, Reflexion und der Permakultur-Ethik können wir unser Leben aktiv und resilient gestalten.</p>\n	</li>\n	<li>\n	<p><strong>Selbstfürsorge und bewusste Lebensweise stärken Resilienz:</strong> Körperliche Gesundheit, Experimente mit Gewohnheiten, natürliche Rhythmen und achtsame Routinen helfen, langfristig im Gleichgewicht zu leben.</p>\n	</li>\n	<li>\n	<p><strong>Permakultur praktisch im Alltag umsetzen:</strong> In Bereichen wie Küche, Wohnen, Mobilität und Konsum zeigen sich permakulturelle Prinzipien – z. B. Vielfalt nutzen, Abfall vermeiden, Ressourcen teilen und nachhaltige Strukturen unterstützen.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1579', '<p>Hier ist die soziale Permakultur verwurzelt. Diversität und Fülle zeigen sich nicht nur in der Natur draußen; auch unsere innere, ganz persönliche Landschaft hat vielfältige Facetten, die erkundet werden können und das Fundament von sozialem Miteinander bilden.</p>\n\n<p>Es mag für uns selbstverständlich sein, im Zuge einer nachhaltigen Zukunft, für unsere Umwelt zu sorgen. Mach dir bewusst, dass eine tiefgreifende Transformation innen beginnt, mit deinen Gedanken und Gefühlen. Diese innere Landschaft wahrzunehmen, zu wertschätzen und zu pflegen ist für mich grundlegend, um auch im Außen, gemeinsam und aktiv das Leben zu gestalten<sup class=\"footnote\">1</sup>. Wann fühlst Du dich lebendig?</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1585', '<p>Zwischenmenschliche Interaktionen bilden ein soziales Gewebe - ein buntes Garn aus Kommunikation und Handeln. Dieses Gewebe entsteht aus unserer inneren Landschaft, also aus den Perspektiven, Erfahrungen und Haltungen, die jeder persönlich in Interaktionen mitbringt.</p>\n\n<p>Ein Thema, das mich viele Jahre lang beschäftigt hat, verdeutlicht diese Entstehung: Wie kann ich wirklich zuhören? Es ist eine Schulung des Herzens, vorurteilsfrei und offen zu lauschen. Eine Grundlage dafür ist die Authentizität – und dar in, mir selbst zuzuhören.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1591', '<p>Räume sind mehr als Wände und Wege. Mit Räumen kann ein architektonischer, geographischer oder zeitlicher Raum gemeint sein – ein Gartenbeet, ein Gemeinschaftsraum oder auch der wöchentliche Treff am Mittwochabend. Es braucht einen Ort, an dem etwas wachsen kann. Das bedeutet: hier treffen sich Umstände, Bedarf und Resonanz in den lokalen Gegebenheiten.</p>\n\n<p>Wie laden wir in einen eckigen Raum das Runde, Harmonische ein und gestalten Strukturen für echte menschliche Begegnung?</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1597', '<p>Soziale Prozesse sind dynamisch, bedingt vorhersehbar und immer lebendig. Wenn wir uns miteinander tief beschäftigen, wächst Verbindung und Resilienz. Beziehungen sind dynamisch, nicht statisch.</p>\n\n<p>In Gewissem Maße sind Phasen vorhersehbar &amp; es können Räume dafür geschaffen werden.</p>\n\n<p><strong>Soziale Phasen</strong></p>\n\n<p>Soziale Prozesse sind lebendig, oft nicht greifbar und für mich Teil unserer immateriellen Kultur. Scott Peck hat ein Modell der Teamentwicklung<sup class=\"footnote\">1 </sup>entworfen, dass aus 4 Phasen besteht. Nach dem Kennenlernen und einer harmonischen Phase, folgen Reibungsprozesse, die notwendig sind für das Gefüge. Danach kann erst Gemeinschaft entstehen. Diese Phasen beginnen neu, wenn sich die Gruppenkonstellation verändert.</p>\n\n<p>Soziale Prozesse sind nie zu Ende, denn mein aktueller Lebensprozess trifft auf den der anderen Gruppenmitglieder.</p>\n\n<p><em>Mini-Beispiel aus dem Alltag. Ein</em><em> sozialer Raum entsteht für eine Stunde und folgt üblichen Mustern: </em><em>Nach einer Fahrradreise landete ich </em><em>in Kiel. </em><em>M</em><em>it einem ÖPNV-Schiff eine Stunde durch den Hafen fahren. Einstieg in Laboe, Unruhe, ankommen, Platzsuche. </em><em>Den neugewonnenen Nachbarn zunicken. </em><em>Stille. Essen auspacken, Gemütlichkeit und Plaudern. Kurz vor dem Hauptbahnhof wieder allgemeine Unruhe und alle steigen aus. </em></p>\n\n<p><strong>Gruppenprozesse</strong></p>\n\n<p>Intention setzen &amp; ausdrücken, Authentizität einladen.</p>\n\n<p>Menschen lernen miteinander! Ohne Offenheit gibt es Streit und Zerwürfnisse.</p>\n\n<p>Meine Erfahrung zeigt: wenn Gruppen, die gemeinsam wirken wollen, in einen ganzheitlichen Prozess eintreten, reicht ein vager Impuls nicht aus. Wünschenswert ist eine starke gemeinsame Vision, die zum Beispiel durch so tolle Methoden wie einen „Traumkreis“<sup class=\"footnote\">2</sup> generiert werden kann. Diese Methode ist aus dem Dragon Deaming entlehnt. Ein Dragon-Dreaming-Prozess<sup class=\"footnote\">3</sup> ist für mich, neben dem Earth-Forum, eine der ganzheitlichsten Methoden für Gruppenprozess</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1603', '<p>Es ist natürlich für uns, regenerativ zu sein! Durch unsere Kultur, Werte und Normen geben wir dynamisch unsere Erkenntnisse und Ideen weiter. Aktiv und bewusst prägen wir so die Zukunft im hier und Jetzt. Kultur ist also nichts Abstraktes – sie zeigt sich in unserem Alltag: wie wir sprechen, entscheiden, Konflikte lösen und miteinander Zeit verbringen.</p>\n\n<p>Ein passendes Zitat von Maja Göpel, Transformationsforscherin: „Wir wirken immer, egal ob wir wollen oder nicht.“</p>\n\n<p><strong>Meine </strong><strong>(innere) </strong><strong>Kultur:</strong><strong> </strong></p>\n\n<p>Was liegt echt, ganz praktisch und machbar in deinem Handlungskreis? Ein Spruch<strong> </strong>aus meiner Kindheit, den ich hin und wieder erinnere:</p>\n\n<blockquote>\n<p>„Gott, gib mir die Gelassenheit, Dinge hinzunehmen, die ich nicht ändern kann, den Mut, Dinge zu ändern, die ich ändern kann, und die Weisheit, das eine vom anderen zu unterscheiden.“</p>\n\n<p>Reinhold Niebuhr</p>\n</blockquote>\n\n<p>Beispiele für transformative Gewohnheiten: Ehrlichkeit, Prozesse zulassen, immer wieder innehalten, Revolution der Langsamkeit, zyklisches Alltagsdesign mithilfe der 8 Schilde</p>\n\n<h6>Kultur in der Gruppe</h6>\n\n<p>Eine Friedenskultur ist kein Zufall ohne Zutun. Ein friedvolles Miteinander entsteht durch passende Räume, innere Intention, gemeinsames Lachen &amp; Schmerz verdauen. Eine verbundene Kultur kann aktiv gebildet werden – mit den richtigen Zutaten. Dazu gehören beispielsweise:</p>\n\n<ul>\n	<li>Kommunikations- und Entscheidungskultur aktiv ausprägen! Passende Werkzeuge sind: Soziokratie, systemisches Konsensieren, Themenzentrierte Interaktion.</li>\n	<li>Phasenübergänge gestalten wie: Meilensteine würdigen, Projekte klar abschließen (z.B. gemeinsame Baustellenbegehung), Veränderungen wie z.B. das Ausscheiden von Gruppen-Mitgliedern feiern und damit das neue Unbekannte einladen.</li>\n	<li>Kleber der Gemeinschaft: Humor (z.B.„running Gag“), gemeinsame Rituale (z.B. der „Wusch“ im Permakultur-Veranstaltungs-Kontext) und Erlebnisse wie eine Kartoffelerntefeier.</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1606', '<ul>\n	<li>\n	<p><strong>Innere Haltung als Grundlage:</strong> Soziale Permakultur beginnt bei der eigenen inneren Landschaft – Selbstreflexion, Umgang mit Gefühlen und persönliche Entwicklung bilden die Basis für ein bewusstes Handeln im Außen.</p>\n	</li>\n	<li>\n	<p><strong>Bewusste Kommunikation und Beziehungen:</strong> Wertschätzende Kommunikation, aktives Zuhören und klare Bedürfnisse fördern Vertrauen, Kooperation und konstruktiven Umgang mit Konflikten.</p>\n	</li>\n	<li>\n	<p><strong>Gestaltung sozialer Räume und Prozesse:</strong> Durch bewusst gestaltete Räume, gemeinsame Entscheidungen und lebendige Gruppenprozesse kann ein nachhaltiges, resilientes Miteinander und eine neue Kultur des Zusammenlebens entstehen.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1613', '<p>„<strong>Was ist daran Permakultur?“</strong> frage ich mich, wenn ich einen offensichtlich naturnah bewirtschafteten Garten sehe. Und die Antwort ist ziemlich einfach: Permakultur ist nicht sichtbar, außer auf einem klaren Hinweisschild. Gewisse Elemente wie eine Komposttoilette können auf ein Kreislaufprinzip schließen lassen, bebenso wie ein Schlüssellochbeet und ein wunderschönes Mischkulturbeet.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1619', '<p>Ein Ökosystem anzulegen braucht Zeit, Balance und liebevolle Pflege.</p>\n\n<p>Das beginnt schon bei der <strong>Beobachtung</strong>. Optimalerweise nimmst Du Dir ein Jahr Zeit mit einem Beobachtungstagebuch, zeichnest vielleicht zu jeder Jahreszeit eine Licht- und Schattenkarte und lernst die Pflanzen kennen. Dazu gehört auch das Träumen, um deinen Visonen und Ideen Ausdruck zu verleihen. Gemeinschaftlich: Traumkreis. Collage, Recherche</p>\n\n<p>Die anschließende Phase der <strong>Analyse</strong> bringt Fokus, Struktur und AHA-Effekte. Die Permakultur-Werkzeugpalette bietet sehr viele Werkzeuge, mit denen Du einfach arbeiten kannst. Z.B. Input Output, …… (Link). Analyse der Gegebenheiten, Strukturen &amp; Entwicklungen vor Ort. Wie z.B. Geologie, Boden, Klima, rechtlicher Rahmen, Bestandspflanzen und mögliche Altlasten. Die Analyse wird z.B. auf Transparentpapieren über dem Grundplan dargestellt und hier ergeben sich klare Muster. Du hast alle Infos zusammen?</p>\n\n<p>Dann kanns ja losgehen mit der <strong>Design</strong>-Phase, um zunächst erste Entwürfen und Ideen zusammen zubringen. Einfache, erste kleine Daumenregeln:</p>\n\n<ul>\n	<li>Kreisläufe schließen (Fokus auf) z.B. Nährstoffe, Wasser, …..</li>\n	<li>Plane 3 verschieden Zeitpunkte, z.B. in 5, 15 und 30 Jahren</li>\n	<li>Schaffe Räume durch verschiedene Höhen, Schichten und Mikroklimata</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1631', '<p>Ein englischer Rasen ist eine Fläche, aber kein wirklicher Raum. Erst mit einer Vision und Gestaltung beginnen Struktur, Räume und Atmosphäre zu wachsen.</p>\n\n<p>Stell Dir vor:</p>\n\n<p><em>In dem Rasen tauchen Pflanzinseln auf, mit Gehölzen, blühenden Stauden und winzigen Bodendeckern. In der Mitte der Rasenfläche fällt dein Blick auf eine Ruheoase, ein kleiner Ort mit Hängematte und Schatten im Sommer, blickdicht gelegen. Eine der Inseln ist ein Teich, hier wuselt und lebt es, ein Libelle brummt an deinem Ohr vorbei. Aus der natürlich kurvenreich angelegten Wildobsthecke tönt ein herrliches Vogelgeschzwitzer. Du bringst die Küchenabfälle vom Mittagessen zum Wurmkomposter und staunst über das gesunde Gewusel! Auf dem Rückweg noch fix ein paar Kräuter einsammeln für heute Abend. </em></p>\n\n<p><em>Das Lagerfeuer wird entzündet, und in den Stockbrotteig werden frisch gepflückte Him- und Tayberrys eingeflochten. Der neben Dir sitzende Mensch erzählt freudig, heute das erste mal eine Zauneidechse bei der Trockensteinmauer gesehen zu haben. Gemeinsam feiert ihr die Diversität!</em></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1637', '<p>Ein Naturgarten kann wild aussehen, muss er aber nicht! Vielfalt ist gleich Stabilität<sup class=\"footnote\">1</sup>, die Biodiversität ist ein unverzichtbarer Bestandteil der komplexen Welt. Symbiosen unterstützen sich, und vielfältige Interaktionen begünstigen eine Balance in einem lebendigem System.<sup class=\"footnote\">2</sup> Ein \"Gärtnerisch geordnetes Durcheinander\" für ein gesundes, pflegeleichtes Gefüge. Nebenbei ist das Gärtnern mit Permakultur-Prinzipien ressourcenschonender, als die klassische Anbauweise.</p>\n\n<ul>\n	<li>Kleine Flächen haben ein riesen Potential! Kleingärten sind die Hotspots der biologischen Vielfalt im besiedelten Raum.</li>\n	<li>Zu Permakultur bewusste Gestaltung der Flächen mit Kreislauffokus. Die Ethik im Naturgarten: ist zukunftsfähig und Bio weiter gedacht - also bis zum Kreislaufende gedacht.</li>\n	<li>Wildtiere brauchen: Zuhause, Futter und Nistmöglichkeiten</li>\n</ul>\n\n<p><strong>Ein Naturgarten auf Basis der Permakultur-Ethik angelegt und gepflegt, ist gut für die Artenvielfalt, erholsam für den Menschen und wunderschön!</strong></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1640', '<ul>\n	<li>\n	<p><strong>Vorbild Natur &amp; ganzheitliches Design</strong><br />\n	Gestaltung orientiert sich an natürlichen Mustern wie Zyklen und Sukzession, um regenerative und vernetzte Systeme zu schaffen. So entstehen nachhaltige Lebensräume für alle Organismen.</p>\n	</li>\n	<li>\n	<p><strong>Langfristiges &amp; systemisches Denken</strong><br />\n	Permakultur denkt über Generationen hinweg und berücksichtigt Verbundenheit, Feedback und Unsicherheiten. Dadurch werden resiliente und bewusste Entscheidungen möglich.</p>\n	</li>\n	<li>\n	<p><strong>Ambivalenzen &amp; Probleme als Chancen</strong><br />\n	Gegensätze und Übergänge fördern Lebendigkeit und Vielfalt im Design. Probleme werden als Chancen genutzt, um kreative Lösungen zu entwickeln.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1656', '<p>Wie ich schon erwähnte: Alles ist ein Prozess. Nicht im juristischen, sondern im lebendigen Sinne. Zwischen Tomaten und Pizzasauce liegt ein Kochprozess, zwischen Kraut und Kimchi eine Fermentation, zwischen Kindheit und Erwachsensein komplexe Entwicklungsprozesse.</p>\n\n<p>Und was bleibt übrig, wenn der Bleistift gespitzt wird?</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1659', '<p><strong>Zusammenfassung – 3 wichtigste Aspekte der Grünen Permakultur:</strong></p>\n\n<ul>\n	<li>\n	<p><strong>Gestaltung nach Bedürfnissen und Möglichkeiten:</strong> Permakultur bedeutet, Flächen (z. B. Balkon, Garten oder Landwirtschaft) individuell und nach den eigenen Ressourcen, Zielen und mit der Permakultur-Ethik zu gestalten.</p>\n	</li>\n	<li>\n	<p><strong>Designprozess mit Beobachtung und Planung:</strong> Ein gutes Permakultur-Design entsteht durch Beobachtung, Analyse und Planung der natürlichen Bedingungen (Boden, Klima, Licht) und wird anschließend schrittweise umgesetzt.</p>\n	</li>\n	<li>\n	<p><strong>Lebendige und vielfältige Ökosysteme schaffen:</strong> Durch vielfältige Elemente wie Mischkulturen, Lebensräume für Tiere, essbare Pflanzen und geschlossene Kreisläufe entstehen nachhaltige, resiliente und artenreiche Landschaften.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1663', '<p>Eine Permakultur-Gestaltung orientiert sich mithilfe von vielfältigen Methoden und systemischem Denken an natürlichen Ökosystemen. Sie vereint in einzigartiger Weise in ihrem ganzheitlichen Ansatz altes und neues Wissen, beispielsweise aus der Biologie, Systemtheorie, Soziologie und dem Management. Die Permakultur-Systematik ist also eine mögliche Herangehensweise zur Lösung von Fragen für die Zukunft.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1664', '<p>Du suchst einen einfachen Kompass im Dschungel der Möglichkeiten?<br />\nDie 3 ethischen Prinzipien, so simpel und kraftvoll, können Dich durch dein ganzes Leben geleiten.</p>\n\n<p><strong>Sorge für die Erde ******* Sorge für die Menschen ******* Faires teilen</strong></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1671', '<p>💥 Du hast eine Projektidee, ein Gelände oder möchtest dein Leben entschleunigen? Hier ist ein wundervolles Werkzeug, das Dir helfen kann: dein Beobachten zu schärfen, Klarheit zu gewinnen und mehr Verbindung zu spüren.</p>\n\n<p>🗝️ MINI-BEOBACHTUNGSZEIT</p>\n\n<p>Mit allen Sinnen, 10 – 30 Minuten lang. Das Beobachten bringt Dich auf den Boden der Tatsachen. Wenn Du raus in die Natur oder deinen Garten gehst, kannst Du gleichzeitig von der Natur lernen und Dich entspannen.</p>\n\n<p>Beobachten bedeutet:</p>\n\n<p>- neutral blicken</p>\n\n<p>- echt fühlen</p>\n\n<p>- tief verstehen</p>\n\n<p><em> LINK zum DOWNLOAD für dein MIN-Beobachtungs-Zine unten!</em></p>\n\n<p>🌀 Bei der Mini-Beobachtung kannst du auch verschiedene Perspektiven einnehmen. Leg Dich doch mal auf dem Boden oder klettere auf eine Erhöhung, lass Dich leiten. Nutze alle deine Sinne! Die Beobachtung hilft uns, Mitgefühl zu entwickeln und in Echtzeit die Gegebenheiten zu erfassen.</p>\n\n<p>Wenn ich Gebäudestrukturen in alten Innenstädten in Ruhe betrachte, wird mir oft dann auch klar, wie und warum etwas gebaut wurde und welchen Zweck die Strukturen vielleicht Generationen vor mir erfüllt haben.</p>\n\n<p>So dürfen wir uns auch wieder etwas von der natürlich-cleveren, weil effektiven, Natur abschauen. In der Natur wird unser Blick geschärft für die Sukzession, Entwicklungsprozesse und Bedingungen unserer Umwelt.</p>\n\n<p><em>Next Step: Eine Übung aus der Wildnispädagogik. Such Dir einen Sitzplatz in der Natur, den Du immer wieder aufsuchst. Beispielsweise einmal am Tag mit einer Tasse wohligem Heißgetränk. Sitze einfach nur mit dem, was da ist.</em></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1672', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1673', '<p>💥 Entscheidungshilfe gesucht! Wie kannst du deine alltäglichen und langfristigen Entscheidungen abwägen? Beispielsweise im Garten: soll das Gewächshaus DIY oder gebraucht gekauft sein? Das Hochbeet mit Folie angelegt werden oder nicht? Jetzt eine schnelle Übergangslösung für einen Riss im Mauerwerk oder doch lieber die aufwendige, aber langfristige Lösung wählen?</p>\n\n<p>🗝️ PERMAKULTUR-ETHIK: Sorge für die Erde – Sorge für die Menschen – Teile gerecht</p>\n\n<p>Die Permakultur-Ethik gibt einen umfassenden Überblick und ist gleichzeitig sehr einfach. Sie geht darüber hinaus, nur einen CO2-Wert zu berechnen. Die Ethik ist optimalerweise ausbalanciert zwischen den drei Prinzipien: Sorge für die Erde, Sorge für die Menschen und Teile gerecht. Das bedeutet, ich bin auch Teil dieser Entscheidung, genauso wie die Natur, meine Umgebung, Ressourcen und das, was ich geben kann. Ein einfaches und effektives Werkzeug!</p>\n\n<p>🌀Im Designalltag arbeite ich oft mit einem Ethik-Schwerpunkt, z.B. eine gewünschte Gartenberatung hin zum Naturgarten. Doch genau das macht Permakultur aus: die Umstände nicht nur einseitig zu betrachten, sondern auch darüber hinaus zu gehen: Wie kann das System zu den anderen zwei Prinzipien beitragen – Sorge für die Menschen und Teile gerecht?</p>\n\n<p>Die Permakultur-Ethik ist erfüllt, wenn wir sie nicht nur punktuell mitdenken sondern als Maximalgedanke zugrundelegen. Ganz praktisch checke ich oft direkt zu Beginn eines Gestaltungsprozesses mit möglichst allen Beteiligten das System. Plötzlich fällt jedem Projektbeteiligten so viel ein! Mit Hilfe der Ethik kann sehr viel Herzblut sichtbar gemacht werden Eine der schönsten, immer wiederkehrenden Momente bei Vorträgen, Veranstaltungen und Beratungen: In der Abschlussrunde teilen Menschen, dass ihnen bewusst wurde, sie praktizieren schon längst unbewusst Permakultur. Toll!</p>\n\n<p>Das ist mehr als nur ein gutes, vertrautes Gefühl: Wir kommen alle auf der gleichen Wertebasis zusammen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1674', '<p>💥 Raus aus: starrem Denken von der Tapete zur Wand. Hole dir Inspiration von natürlichen Zyklen und orientiere dich an der Sprache der Natur!</p>\n\n<p>🗝️ NATURRHYTHMEN</p>\n\n<p>Ein rhythmisches Leben zu leben, verbindet uns wieder mit der Natur, lässt uns aufladen und auftanken Die Prozesshaftigkeit des Lebens zu spüren, schenkt Entschleunigung.</p>\n\n<p>🌀 Beispiele für Naturrhythmen:</p>\n\n<p>Ebbe und Flut, Jahreszeiten, 8 Schilde, Astronomie, Frucht- und Gemüseentwicklung, unser Biorhythmus (wir sind Natur, circadianer, lunarer, ultradianer Rhythmus)<sup class=\"footnote\">1</sup></p>\n\n<p>Das ist unser ganz individueller Rhythmus, Kontext und Perspektive. Astronauten können 16 Sonnenauf- und Untergänge pro Tag sehen. Ich nur je einen.</p>\n\n<h6>Praktische Inspirationen:</h6>\n\n<ul>\n	<li>Erforschung und Anwendung in deinem Alltag z.B. ein phänologisches Tagebuch,</li>\n	<li>Leben mit und in den Jahreszeiten und ihren Qualitäten (8 Schilde)</li>\n	<li>Im Garten mit den Jahreszeiten gestalten, Blühzeitpunkte, Ruhe im Winter.</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1684', '<p>Von der Frage bis zum ganzheitlichen Design – drei passende Formate für dein Anliegen. Hast Du auch Lust auf ganzheitliche Lösungen für regenerative Lebensräume? Ich freue mich auf deine Anfrage!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1685', '<h6>Hier gibt es eine Sammlung aus Material, dass Du dir herunterladen kannst. Wenn Du möchtest, kannst Du hier etwas dafür geben auf PayPal. Senden an: post@herrliche-permakultur.de</h6>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1687', '<p>Ich liebe den bunten Permakultur-Strauß mit allen Anteilen: grün, sozial und zyklisch. Die Permakultur-Weiterbildung war für mich wie in jeder klassischen Ausbildung: 7 Jahre lang Grundlagen erfahren, danach vertiefe ich mein Wissen in der Praxis und verknüpfe die Leidenschaft zur Profession.</p>\n\n<p>Ich habe viele verschiedene Projekte betreut und umgesetzt, beispielsweise von einer Food-Coop gründen, einen inklusiven Schrebergarten alters- und rollstuhlgerecht designen, innerhalb eines interaktiven Workshops eine Solidarische Landwirtschaft im grünen und sozialen Raum geplant, bis hin zu einem rein sozialen Projekt: der Gestaltung eines passenden Abschiedsrituales in meinem Palliativ-Team.</p>\n\n<p>In meiner Arbeit vertraue ich dem Prozess und bin auf der Suche nach alternativen, ehrlichen und fairen Lösungen, die möglichst simpel sind und Sinn ergeben.</p>\n\n<p>Auf dass sich Kompost bilden möge in den Rissen dieser Welt damit wir darin Wurzeln können.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1688', '<p>Carolin Herrlich</p>\n\n<p>- Herrliche Permakultur -</p>\n\n<p>post@herrliche-permakultur.de</p>\n\n<p>Tel: 01634492942</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1689', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1690', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1691', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1692', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1694', '<p>Begründer der Permakultur sind Bill Mollison und David Holmgren, die in Australien Ansätze für eine nachhaltige Landwirtschaft – <em>permanent agriculture</em> - suchten. Sie fragten sich: Was wäre, wenn es eine Landbewirtschaftung gibt, die zwar nicht wie ein Wald aussieht, aber so funktioniert?<sup class=\"footnote\">1 </sup>Seit den 1970er Jahren entwickelt sich die Permakultur weltweit und bildet komplexere Prozesse, Dynamiken und Ideen ab, beispielsweise mit der sozialen Permakultur.</p>\n\n<p><br />\nEin Permakultur-Design kann sich beispielsweise beziehen auf: Tagesablauf, Schreibtischordnung, Gemüsegarten, Stadtteilfest, Solidarische Landwirtschaft, Arbeitsumfeld, etc.</p>\n\n<p><br />\n„Permakultur“ ist eine innere Haltung, ein äußerer Kompass und bewusste Zukunftsgestaltung mit Hand, Herz &amp; Verstand! Ebenso bedeutsam: dem Prozess zu vertrauen. Wenn ich einfach nur ein statisches Design anstrebe, würde ich damit die aktuellen Muster in der Welt reproduzieren. Ich suche nach anderen, ehrlichen, sinnvollen und fairen Lösungen, die interagieren &amp; integrieren. Auf dass sich Kompost bilden möge in den Rissen dieser Welt, damit wir darin wurzeln können.<br />\nSinnvoll in einem individuellen Kontext angewendet, ist es uns möglich über den ersten Augenblick hinauszusehen und die großen, langfristigen, und damit nachhaltigen Veränderungen, heute im Kleinen anzustoßen.</p>\n\n<p>Einstein:</p>\n\n<blockquote>\n<h6>\"Man sollte alles so einfach wie möglich machen, aber nicht einfacher.\"</h6>\n</blockquote>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1695', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1696', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1697', '<p>Du überlegst, etwas zu gestalten oder umzusetzen? Nimm Dir eine kurze Atempause Zeit für einen Mini-Check: Habe ich die 3 Ethiken bedacht?</p>\n\n<p><br />\nFür mich ist die Permakultur-Ethik das wichtigste Werkzeug, das Fundament unseres Denkens, Planens und Handelns. Sie dürfen auf dem Permakultur-Weg zu einer natürlichen inneren Haltung werden. Die goldene Mitte ist für mich persönlich Ankerpunkt und Grundlage der Balance: Menschlichkeit, Vielfalt, Inklusion<sup class=\"footnote\">1</sup>. So bildet sich Stück für Stück, mit unseren Erfahrungen und Designs, natürliche Weisheit heraus.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1700', '<h6><strong>1. Ganzheitlich beobachten</strong></h6>\n\n<p>Mit den neugierigen Augen eines Kindes beobachten und mit allen Sinnen erfahren. Möglichst neutral wahrzunehmen schafft Verbindung: beispielsweise mit uns selbst, den Pflanzen und den Mitmenschen. So finden wir ganz einfach Möglichkeiten, Probleme und Zusammenhänge in den betrachteten Systemen. Beobachten entschleunigt und bildet die wohltuende Grundlage für unsere Gestaltung.</p>\n\n<h6><strong>2. Komplex denken</strong></h6>\n\n<p>...heißt nicht kompliziert. Aus unserer menschlichen und kulturell geprägten Perspektive können wir oft nicht alle Ursachen und Wirkungen sofort sehen. Es geht eher um ein systemisches Denken, welches auch immaterielle &amp; saisonale Faktoren mitbedenkt. Wenn wir vom großen Ganzen bis in kleinste Details schauen, können wir grundlegend und möglichst neutral analysieren. Das ist ein Fundament für echte, nachhaltige und kontextangepasste Lösungen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1701', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1702', '<h6><strong>3. Flexibel planen</strong></h6>\n\n<p>Diese Planungs- oder auch Designphase ist geprägt von Entwürfen. Manchmal fühlt es sich magisch an: die Gegebenheiten lassen logische Schlüsse zu. Manche Ideen „klicken“ genau an die richtige Stelle und auf einmal ergibt alles Sinn und findet seinen richtigen Platz im Ökosystem.<br />\nWichtig ist eine Offenheit, den Erstentwurf nochmal zu überarbeiten und anzupassen. Das Leben geht seine eigenen Wege, Materialien sind auf einmal doch nicht zur Verfügung, dafür aber andere Möglichkeiten. Bleib dran, Du lernst mit jedem vertieften Prozess!</p>\n\n<h6><strong>4. Ganzheitlich handeln</strong></h6>\n\n<p>Durch die intensive Beschäftigung mit einem System ist es uns nun möglich, fundierte Entscheidungen zu treffen, die unserem ethischen Kompass dienen. Die Dinge werden oft einfach und klar. Ganzheitlich handeln bedeutet in der Permakultur: für die nächsten sieben Generationen, Tiere, Pflanzen, Pilze und Mineralien - zyklisch und resilient.</p>\n\n<h6><strong>***** Feiern! *****</strong></h6>\n\n<p>\"Die Dinge rund machen\", Danke sagen. Deine soziale Qualitätszeit zelebrieren und genießen. Es gibt viele Gründe, bewusstes Feiern und Lächeln immer wieder einzuladen!!!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1703', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1706', '<p>Für ein zusammenhängendes, sinnvolles und verbundenes Mosaik brauchen wir zuerst eine Idee vom Gesamtbild, bevor wir die einzelnen Mosaiksteine legen und danach verbinden zu einem Gesamtkunstwerk.</p>\n\n<p>Zuerst kommt das Muster: Neben der Terrasse ist ein guter Platz, um Gemüsebeete anzulegen. Danach folgt die Entscheidung der Details, wie die Beetform und Bepflanzung.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1707', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1710', '<p>Ad hoc handeln - mit dem Kopf direkt durch die Wand - war gestern. Zukunftsfähig ist klares, schrittweises Handeln mit Herz und Ethikbewusstsein. Auch ein großer Baum wächst aus einem kleinen Samen unter den richtigen Bedingungen.</p>\n\n<ul>\n	<li>Flächen vorbereiten: abdecken, dick abmulchen, lebendige Gründüngung</li>\n	<li>Biokompost vergraben bei geplanten Baumpflanzstellen</li>\n	<li>Holzhäcksel plus Stickstoff verwenden zur langfristigen Bodenverbesserung</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1711', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1714', '<p>Was ich aus meiner antropozentrischen Sichtweise als Problem wahrnehme, kann eine Lösung sein! – zuwenig Geräte, zuwenig Platz, zuviel Unkrautdruck<br />\n#Probleme sind dornige Chancen z.B.:</p>\n\n<p><br />\n• die sehr trockene Stelle im Garten ist ein perfektes Magerbiotop<br />\n• ich bin gestresst heißt: ich nehme mir eine bewusste Auszeit zur Regeneration in der Sauna<br />\n• Abgrenzung zum Nachbarn: eine Wildobsthecke anlegen = essbar und wunderbarer Naturraum UND Sichtschutz</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1715', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1716', '<p>Um unsere Gestaltungsüberlegungen während des Prozesses zu reflektieren, können wir verschiedene Prinzipien-Sets nutzen. Meiner Erfahrung nach stellen wir dabei oft fest, ob unser Design oder unsere Überlegungen verschiedene Aspekte bedacht haben. Ich habe mittlerweile Spaß daran gefunden, bei einer Planung mit mehreren Prinzipiensets zu arbeiten, um dem Design noch mehr Tiefe zu verleihen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1717', '<p>Auf der Erde geht nichts verloren, im geschlossenen Prozess unserer kleinen, planetaren Heimatkugel. Im steten Ablauf von Entwicklung durch Werden &amp; Vergehen, entfaltet sich das natürliche Leben auf der Erde. Ein ganzheitliches Leben ist und verläuft zyklisch. Das Kreislauf-wirken in unserer wundervollen Natur ist ein Bestandteil eines ganzheitlichen Lebens.</p>\n\n<p>Unsere anthropozentrische, globale Welt ist spezialisiert darauf, Kreisläufe zu öffnen, aber nicht zu schließen<sup class=\"footnote\">1</sup>. Als Gegenentwurf wurde die der grünen, landbasierten Permakultur entwickelt. Einer der Kernpunkte, die Kreislaufwirtschaft, ist fester Bestandteil des Designs bezüglich Wasser, Nährstoffen und Ressourcen. Beispielsweise im Bereich der Architektur &amp; des ökologisches Bauen, wurden unlängst sehr viele kreative, systemisch gedachte Kreislaufideen entwickelt. Das sind zum Beispiel Pilze als Baustoffe, vertikales Begrünen, wassersparendes Design, Lehmwände, Rezyklieren, Urban Mining, etc ... Neue Ansätze mit Kreislaufgedanken verdeutlichen: Es ist möglich!</p>\n\n<p>Wenn wir unser Leben, Beziehungen, Arbeit, Gärten, Prozesse und Umgebung umfassend zyklisch gestalten, kann sich Zufriedenheit, Harmonie &amp; natürliche Ganzheitlichkeit entfalten.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1718', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1719', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1721', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1722', '<p>Die 8 Schilde waren für mich vor einigen Jahren, zu Beginn meines Permakultur-Weges eine Art Prozessmodell<sup class=\"footnote\">2 </sup> oder Prinzipienset im Designalltag. Mittlerweile ist diese Systematik, gemeinsam mit der Ethik, zu meinem inneren Kompass geworden: im Alltag, im sozialen Miteinander<sup class=\"footnote\">3</sup> und natürlich auch im Garten – da schaue ich mir jeden Tag etwas von der Natur ab. :)</p>\n\n<p>Ich habe mit Hilfe der 8 Schilde diverse Gestaltungen gemacht: Partys, Kurse, Gruppenübungen, Abschiedritualfindung, Tag, Kochen für eine Gruppe, Gartenbauwoche, ...</p>\n\n<p>Nach dem Motto: „Keine halben Sachen!“</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1724', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1726', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1731', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1734', '<p>10.-12.04.2026, Projekt ToGenJi in Steyerberg, nahe Hannover</p>\n\n<p>Ein authentisches Leben orientiert sich im Kreislaufprinzip an deiner individuellen Wahrnehmung, Gefühlen, Rhythmus &amp; Geschwindigkeit. Durch bewusstes Durchschreiten von Prozessen – mit gutem Anfang &amp; Reflexion am Ende – übernimmst Du aktiv das Steuer deines Lebens. Das universelle Modell der 8 Schilde ist in diesem Kurs unser Kompass, Prozessmodell und Prinzipienset.</p>\n\n<p><strong>Auf einem der ältesten Permakultur-Gelände Europas entdecken wir gemeinsam vielfältige Muster des zyklischen Lebens </strong><strong>und Ankerpunkte im Kreislaufprozess</strong><strong>. </strong><strong>A</strong><strong>lle Aspekte des Lebens sind hier herzlich willkommen: Verstand, Gefühle, Herz und </strong><strong>Hand.</strong><strong> </strong><strong>Dich erwarten Gestaltungsinspirationen zu großen und kleinen Zyklen, zum Beispiel die Sand-Reflexion oder „verrückte Schwelle“.</strong></p>\n\n<p>Permakultur beginnt in jedem von uns als Samenkorn, welches sich zu einer regenerativen und zukunftsfähigen, kollektiven Perspektive entwickelt. Das ist die neue Kultur, die wir als Kursleitende seit Jahren bewusst wachsen lassen. Gemeinsam erforschen wir natürliches Leben, Elemente im Alltag und verbundenes Handeln.</p>\n\n<p>Der Frühlingsanfang als Kurszeitpunkt biete die Qualiäten von Orientierung, Neugierde und Gestaltung des „Guten Anfangs“. Finde hier in einer geborgenen und reizreduzierten Kursumgebung viele Möglichkeiten, aktiv in die Prozessgestaltung deines Lebens zu kommen!</p>\n\n<p>Was Dich erwartet:</p>\n\n<ul>\n	<li>Input zu natürlichen Zyklen: Grundlagen und verschiedene Kreislaufmuster</li>\n	<li>Praktische Übungen und Impulse, um deinen Kompass zu schärfen.</li>\n	<li>Erkunden des Permakultur-Geländes</li>\n	<li>Eigene Ernte aus unserem Permakultur-Garten und genussvolles, biologische Essen</li>\n	<li>Körperübungen, Yoga- und Zen-Meditation</li>\n	<li>Zeit zum tiefen Austausch in unserer Gruppe</li>\n</ul>\n\n<p>Bitte mitbringen:</p>\n\n<ul>\n	<li>Yogamatte</li>\n	<li>Pflanzen/ Saatgut</li>\n	<li>Eigenes Notizheft für achtsames Tagebuch führen</li>\n	<li>der Witterung angepasste Outdoor/Gartenkleidung</li>\n	<li>gerne Essen zum teilen</li>\n</ul>\n\n<p>Anreise: Fr. ab 16 Uhr<br />\nBeginn: Fr. 17 Uhr<br />\nEnde: So. 13 Uhr nach dem Mittagsessen<br />\nAnmeldeschluss: 01.04.2026<br />\nMax. Teilnehmerzahl: 12</p>\n\n<p>Die Kosten für Unterkunft &amp; Verpflegung werden von der Choka Sangha vorgegeben.<br />\nDie Kursgebühr beträgt mind. 200 €/ Teilnehmer, je nach insgesamter TN-Zahl</p>\n\n<p>Leitung: Nathalie Vordenbäumen (<a href=\"mailto:natvor@gmx.de\">natvor@gmx.de</a>) und Carolin Herrlich</p>\n\n<p>Im Tempel und auf dem Gelände gibt es ein Mehrbettzimmer für Frauen und ein Matratzenlager in der Zendo (Meditationshalle). Auch Zelte können mitgebracht werden. Eigeninitiativ können auch Einzel- oder Doppelzimmer im Lebensgarten (10 Minuten Fußweg) gebucht werden. Kontakt: <a href=\"mailto:chriswax@t-online.de\">chriswax@t-online.de</a> oder 05764 941670.</p>\n\n<p>Eine Infomail folgt vor dem Kurs.</p>\n\n<p><strong>KEEP GROWING!</strong><br />\nDeine Nathi und Caro</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1735', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1738', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1741', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1742', '<h6>Individuelle Kurzberatung – fokussiert, persönlich und wirkungsvoll.</h6>\n\n<p>Diese 1:1-Onlineberatung eignet sich besonders, wenn du:</p>\n\n<ul>\n	<li>\n	<p>konkrete Impulse für deinen Garten, dein Projekt oder andere Lebensräume suchst</p>\n	</li>\n	<li>\n	<p>eine klare, strukturierte Beratung möchtest</p>\n	</li>\n	<li>\n	<p>über das Gespräch hinaus Anregungen für die nächsten Schritte brauchst</p>\n	</li>\n</ul>\n\n<p>Vor unserem Termin erhältst du einen detaillierten Fragebogen. So kann ich mich gezielt auf deine Situation vorbereiten und unsere gemeinsame Zeit optimal nutzen.</p>\n\n<h6>Ablauf</h6>\n\n<ul>\n	<li>\n	<p>Fragebogen &amp; Terminvereinbarung</p>\n	</li>\n	<li>\n	<p>1 Stunde persönliches Online-Beratungsgespräch</p>\n	</li>\n	<li>\n	<p>weiterführende Impulse &amp; Materialien</p>\n	</li>\n	<li>\n	<p>zusätzlich: 1 Ticket für eine Permakultur-Sprechstunde</p>\n	</li>\n</ul>\n\n<h6>Rahmen</h6>\n\n<p>🧭 online | 1:1<br />\n⏱ Dauer der Beratung: 1 Stunde<br />\n🔁 Preis: 150 - 250€ (solidarisches Preismodell, Selbsteinschätzung)<br />\n💎 inkl. 1 Ticket zur Permakultur-Sprechstunde</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1743', '<h6>Permakultur-Sprechstunde – offen für dich &amp; deine Fragen.</h6>\n\n<p>Du stehst vor einer Herausforderung in deinem Garten, Projekt oder Lebensraum? Permakultur denkt ganzheitlich – und genau dafür ist diese Sprechstunde da.</p>\n\n<p>In der monatlichen Online-Sprechstunde treffen wir uns in einer kleinen Gruppe. Wir beginnen bewusst im Redekreis, um anzukommen und einen offenen, wertschätzenden Raum zu schaffen. Anschließend beantworte ich eure Fragen aus der Perspektive der Permakultur – praxisnah, systemisch und lösungsorientiert.</p>\n\n<p>Wenn du möchtest, kannst du mir deine Frage bereits bei der Anmeldung schicken, damit ich mich gezielt vorbereiten kann. Je nach Zeit gibt es zusätzlich einen kurzen Mini-Input zur Inspiration.</p>\n\n<h6>Ablauf</h6>\n\n<ul>\n	<li>ca. 30 Min. Ankommen &amp; Redekreis</li>\n	<li>ca. 45 Min. offene Fragerunde</li>\n	<li>ggf. Austausch oder Mini-Input</li>\n</ul>\n\n<h6>Rahmen</h6>\n\n<p>🧭 online | Gruppen-Call | 1× im Monat<br />\n⏱ Dauer: 1,5 Stunden<br />\n🔁 Preis: 25 €<br />\n💎 max. 15 Teilnehmende</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1748', '<p>Offene Online-Sprechstunde in einer Gruppe für deine Permakultur-Fragen.<br />\nGemeinsam ankommen, austauschen und konkrete Impulse mitnehmen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1749', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1753', '<p>Du möchtest aufbauend sein und zukunftsfähig handeln. Was findest Du sinnvoll und möchtest es unterstützen? Wenn Du es noch nicht weißt: probiere die Ikigai-Methode.</p>\n\n<p>Es gibt abertausende und noch mehr fantastische Ideen, Initiativen und kreative Menschen.</p>\n\n<p>Deine Startfrage: Wo erlebst Du Dich wirkungsvoll und gestaltend? KKKKKK Circle of Condern.</p>\n\n<p>Im Folgenden findest Du ein paar wenige von unzähligen, großartigen und wirkungsvollen Beispielen:</p>\n\n<ol>\n	<li><strong>Dein direktes Umfeld</strong> (Zeitwohlstand, nachhaltiges Arbeiten, naturnaher und insektenfreundlicher Garten, pro-igel.de, Saatgut und Ernteüberschüsse teilen, Nachbarschaftsfest organisieren, Solawi, Hofläden, Fairteiler nutzen &amp; pflegen, nebenan.de, ...)</li>\n	<li><strong>Lokal (</strong>Petitionen unterschrieben,Vereine wie NABU und BUND unterstützen, Müll sammeln, Gemeinschaftsgärten, Ackerhelden, Flohmärkte, Kleinanzeigen, Repair Café, Leihladen, Bürgerbeteiligung, ...)</li>\n	<li><strong>Global </strong>(globale Organisationen wie Peta/ Greenpeace/ Amnesty/ Sea-watch/ Oxfam/ Ärzte ohne Grenzen, alternativer Tourismus, über den Tellerrand schauen, Crowdfunding, Tierretter)</li>\n</ol>\n\n<p>Thích Nhất Hạnh sprach von einer globalen Ethik<sup class=\"footnote\">1</sup>, die wir allmählich ausbilden dürfen. Global denken, lokal handeln!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1759', '<p>Essen verbindet und macht Spaß. Im ersten Permakultur-Garten, den ich mitbetreuen durfte, entbrannte meine Leidenschaft für buntes, gesundes und außergewöhnliches Essen.</p>\n\n<p>Herznuss, Maulbeere, Ölweide, Weinbeere, Mini-Kiwi, Taglilienblüten, … Ein herrlicher Genuss der Vielfalt bringt mich sofort zum lächeln!</p>\n\n<p>In unserer Klimazone hat der vielschichtige Wald schon immer eine wichtige Bedeutung für unsere Ernährung. Möglicherweise ist Europa überhaupt erst besiedelt werden konnte, weil es die Haselnuss gab<sup class=\"footnote\">1</sup>. Ein Hoch auf die Haselnuss! Davon gibts übrigens mindestens 13 verschieden Sorten, unter anderem die „Hallesche RiesenNuss“.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1762', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1763', '<p><strong>Meine Ausbildung und berufliche Laufbahn umfassen:</strong></p>\n\n<ul>\n	<li>\n	<p>Fachabitur, Fachkrankenpflegerin für Onkologie und 10 Jahre Arbeit in diesem Bereich</p>\n	</li>\n	<li>\n	<p>Permakultur-Design-Kurs (2018) – <em>Seitdem Mitarbeit in verschiedenen Projekten, darunter ein 3-monatiges Projektmanagement auf Sri Lanka mit der Permakulturschule Österreich.</em></p>\n	</li>\n	<li>\n	<p>Fachberaterin für Selbstversorgung mit essbaren Wildpflanzen (2019).</p>\n	</li>\n	<li>\n	<p>Permakultur-Ausbildung (2020-2025) an der deutschen Permakulturakademie</p>\n	</li>\n	<li>\n	<p>Diplomierte Permakultur-Gestalterin seit 2025</p>\n	</li>\n	<li>\n	<p>Tutorin für die deutschlandweite Ausbildung seit 2026</p>\n	</li>\n	<li>\n	<p>aktuelle Ausbildungen: Fernstudium der Gartenplanung und Ausbildung \"Inner Freedom Work\" (Permakultur des Herzens)<sup class=\"footnote\">1</sup></p>\n	</li>\n</ul>\n\n<p><strong>Berufserfahrung und Projekte:</strong></p>\n\n<ul>\n	<li>\n	<p>Facilitator in mehreren zweiwöchigen Permakultur-Designkursen (2020-2023).</p>\n	</li>\n	<li>\n	<p>Durchführung von Permakultur-Einführungskursen und Workshops zum Geländedesign.</p>\n	</li>\n	<li>\n	<p>Beratung und Planung von Lebensmittelkooperativen und mehreren Selbstversorgergärten.</p>\n	</li>\n	<li>\n	<p>Nützlingsbiotope im Hausgartenbereich und auf dem ältesten Permakultur-Gelände Europas (Choka Sangha e.V.).</p>\n	</li>\n	<li>\n	<p>Planung einer Solidarischen Landwirtschaft auf 1,5 ha (Greene).</p>\n	</li>\n	<li>\n	<p>Betreuung des Permakultur-Nord-Netzwerks und Mitarbeit am Permakultur-Küchen-Projekt.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1764', '<p><strong>Vision</strong></p>\n\n<p>Meine Vision ist es, Verbindung und lösungsorientiertes Denken wieder zu stärken und in die Gesellschaft zu integrieren. Ich möchte einen Raum schaffen, in dem wir uns als Menschen echt begegnen können, uns in unseren Bedürfnissen wahrnehmen und gemeinsam verantwortungsbewusst und authentisch leben.</p>\n\n<p>Die Zyklen des Lebens zu verstehen und natürliche Rhythmen zu kultivieren, ist dabei ein zentraler Bestandteil meines Ansatzes. Für mich bedeutet Permakultur nicht nur nachhaltige Garten- und<strong> </strong>Landschaftsgestaltung, sondern die Schaffung von heilungsfördernden Biotopen für Menschen und Natur. Ich möchte, dass wir den Kreislauf als Normalität sehen – Abschiede ebenso feiern wie neue Anfänge, und Reflexion und Integration als fortlaufende Prozesse begreifen.</p>\n\n<p>Durch meine Arbeit möchte ich die vielfältigen Potenziale von Menschen, Gemeinschaften und Ökosystemen sichtbar machen und sie mit nachhaltigen, kreativen Lösungen unterstützen. Gemeinsam wollen wir Wunder entdecken, die uns umgeben – von den kleinen Momenten bis zu den großen Veränderungen. In meinen Permakultur-Prozessen unterstütze ich Menschen dabei, ihre eigene Kreativität und<strong> </strong>Wirksamkeit zu entfalten, um wirklich nachhaltige, an den Kontext angepasste Designs zu entwickeln.</p>\n\n<p><strong>Meine Herzenswünsche:</strong></p>\n\n<ul>\n	<li>\n	<p>Mehr Verbindung zwischen Menschen und ihren natürlichen Lebensräumen.</p>\n	</li>\n	<li>\n	<p>Fokus auf das Gemeinsame, auf das, was uns eint und uns voranbringt.</p>\n	</li>\n	<li>\n	<p>Kreislaufdenken als fundamentale Haltung zu kultivieren und Veränderung als natürlichen Teil unseres Lebens zu betrachten.</p>\n	</li>\n	<li>\n	<p>Unsere grünen Oasen und heilsamen Lebensräume zu genießen, mit einem Gefühl von Genuss und Genügsamkeit.</p>\n	</li>\n</ul>\n\n<p><strong>Zitat von John Krabat Zinn</strong>: <em>„Die kleinen Dinge. Die kleinen Momente. Die sind nicht klein.“</em></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1765', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1768', '<p><strong>Permakultur erleben – lebendig, praxisnah und inspirierend.</strong><br />\nIch biete Vorträge, Kurse und Workshops rund um ökologische Gestaltung, soziale Prozesse und zyklisches Denken. Für alle, die Zukunft aktiv mitgestalten wollen.</p>\n\n<p>In meinen Vorträgen, Kursen und Workshops vermittle ich Permakultur als ganzheitlichen Gestaltungsansatz für Gärten, Landschaften, Gemeinschaften und innere Prozesse. Theorie und Praxis greifen ineinander – mit Raum für Fragen, Austausch und eigene Erfahrungen.</p>\n\n<p>Meine Veranstaltungen richten sich an:</p>\n\n<ul>\n	<li>\n	<p>junge Menschen, die Permakultur lernen und leben wollen</p>\n	</li>\n	<li>\n	<p>Initiativen, Projekte und Gruppen mit ökologischem oder sozialem Fokus</p>\n	</li>\n	<li>\n	<p>Menschen, die Zukunft bewusst, freudvoll und verantwortungsvoll gestalten möchten</p>\n	</li>\n</ul>\n\n<p>Dabei verbinde ich <strong>grüne, soziale und zyklische Permakultur</strong> – immer angepasst an den jeweiligen Kontext und die Menschen vor Ort.</p>\n\n<p>Mögliche Themenbereiche:</p>\n\n<p>Permakultur Einführung, Workshop Gartengestaltung, Alegen einer essbaren Landschaft, Zyklische Permakultur, ...</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1769', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1770', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1773', '<p>Als diplomierte Permakultur-Designerin begleite ich Menschen, Gruppen und Projekte dabei, <strong>zukunftsfähige Lebensräume</strong> zu gestalten – vom Kleingarten über Gemeinschaftsprojekte bis hin zu öffentlichen Räumen.</p>\n\n<p>     ökologisch • gemeinschaftlich • prozessorientiert</p>\n\n<p>ich finde gemeinsam mit Euch und einem Permakulturprozess ein wirklich nachhaltiges Design angepasst auf den jeweiligen Kontext.</p>\n\n<p>Für eine persönliche Beratung habe ich ein niedrigschwelliges Angebotspaket geschnürt – online – Kurzberatung. Siehe Link am Ende der Seite.</p>\n\n<p>Für eine weitergehende, umfassendere Begleitung vor Ort kannst Du mich auf Stundenbasis buchen. Ich freue mich auf deien Anfrage!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1774', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1777', '<p>Die Welt ist voller Möglichkeiten! Mit meiner Arbeit möchte ich diese vielfältigen Potenziale von Menschen, Gemeinschaften und Ökosystemen sichtbar machen &amp; nutzen.</p>\n\n<p>Um die Welt von morgen bewusst im Hier und Jetzt gestalten zu können lass dich inspirieren:</p>\n\n<p>- Blog</p>\n\n<p>- Sprechstunde</p>\n\n<p>- Werkzeugpalette</p>\n\n<p>- Wissenspakete</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1785', '<p>Entwickle mit der Frühjahresenergie dein ganzheitliches Lebens-System!</p>', '');
