INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2219', '<p>Fünf vielfältige Ideen zur Umsetzung:</p>\n\n<ol>\n	<li>Obstbaumgilde,</li>\n	<li>Naschwege,</li>\n	<li>Teekräuterbeet,</li>\n	<li>essbares Spalier</li>\n	<li>moderner Bauerngarten</li>\n</ol>\n\n<h6>Na, schon Apetit bekommen?</h6>', '');
