INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2227', '<p>Natürliche Vorbilder:</p>\n\n<ul>\n	<li>Baumstamm,</li>\n	<li>Blitze ,</li>\n	<li>Blattrosette bei zweijährigen Stauden...</li>\n</ul>\n\n<p>Menschliche Nachahmung:</p>\n\n<ul>\n	<li>Vision einer Gruppe,</li>\n	<li>detailliertes Zone 1- Design,<sup class=\"footnote\">1</sup></li>\n	<li>Küche im Haus als Lebensmittelpunkt</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2228', '<p>Natürliche Vorbilder:</p>\n\n<ul>\n	<li>Entwicklung einer Fläche hin zu Wald<sup class=\"footnote\"><span style=\"background-color:#fcc000;font-size:12px;\">2</span></sup>,</li>\n	<li>Baumwachstum,</li>\n	<li>Moosentwicklung</li>\n</ul>\n\n<p>Menschliche Imitation:</p>\n\n<ul>\n	<li>Lebensveränderungen, das älter werden mit einplanen,</li>\n	<li>größer werdende Bäume mit den Jahren nutzen (Obstbaumgilde),</li>\n	<li>lebendige Bauten mit Weiden</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2229', '<p>Natürliche Vorbilder:</p>\n\n<ul>\n	<li>Wasserkreislauf,</li>\n	<li>Nahrungsnetzwerke (<em>statt Nahrungskette</em>),</li>\n	<li>positive und negative Rückkopplung im Ökosystem</li>\n</ul>\n\n<p>Menschliche Imitation:</p>\n\n<ul>\n	<li>Cradle 2 Cradle,</li>\n	<li>Kompostierung,</li>\n	<li>Feedbackschleife</li>\n</ul>', '');
