INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2234', '<p>Online, 1:1 oder vor Ort – individuell für Dich!</p>\n\n<p>Permakultur-Sprechstunde l Kurzberatung l individuelle Beratung</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2235', '<p>Zum herunterladen, gib was Du möchtest.</p>\n\n<p>Hol Dir deinen Startimpuls!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2236', '<p>Naturgarten-Grundsätze:</p>\n\n<h6>Torf- und Giftfrei</h6>\n\n<ul>\n	<li>biologisch düngen,</li>\n	<li>Baumaterialien möglichst regional und</li>\n	<li>Kunststoff vermeiden</li>\n</ul>\n\n<h6>Heimische Pflanzen verwenden</h6>\n\n<ul>\n	<li>lt. Naturgarten e.V.<sup class=\"footnote\">3</sup> bei den Zierpflanzen mind. 50% heimischer Wildpflanzenanteil, ich empfehle 90% anzustreben, das bedeutet auch: Begrenzung von invasiven Arten.</li>\n	<li>Die mit großem Abstand größte Fülle an Blütenpflanzen finden wir auf magen Böden. Es lohnt sich, magere Orte im Garten zu nutzen und zu erweitern.</li>\n</ul>\n\n<h6>Blüten von Frühling bis Winter</h6>\n\n<ul>\n	<li>gestalten mit verschiedenen Pflanzenfamilien, z.B. geophyten. Natura DB ist eine tolle Unterstützung.<sup class=\"footnote\">4</sup></li>\n	<li>Tiere pflanzen: es gibt generalistische Insekten und sehr spezielle, die sich nur von einer bestimmten Pflanze, bzw. dem Pollen und Nektar, ernähren.<sup class=\"footnote\">5</sup></li>\n</ul>\n\n<h6>Vielfalt feiern</h6>\n\n<ul>\n	<li>artenreicher Krautsaum unter deiner Hecke,</li>\n	<li>mehr Toleranz im Garten z.b für sogenannte Unkräuter.</li>\n	<li>Modellierung des Geländes für unterschiedliche Lebensräume, Mikroklima und verschiedene Strukturen (Blätterhaufen, Steinpyramiden, Totholzhecke).<sup class=\"footnote\">6</sup></li>\n</ul>\n\n<h6>Umsichtig gärtnern und extensive Pflege</h6>\n\n<ul>\n	<li>Naturfördernde Pflagemaßnahmen, wie verblühte Pflanzenteile möglichst lange stehen lassen.<sup class=\"footnote\">7</sup></li>\n	<li>Wenn entkrautet wird, dann am besten im Spätsommer und Herbst. Invasive Arten, wie die kanadische Goldrute, empfehle ich ab April alle 2 Monate auszusortieren.</li>\n	<li>Statt Einheitsrasen ein Blumenkräuterrasen, Pflege mit einer Mosaik- oder Staffelmad, am besten mit der Sense.</li>\n</ul>\n\n<h6>Kreisläufe schließen für die Nachhaltigkeit</h6>\n\n<ul>\n	<li>biologische Masse im Garten halten nund kompostieren,</li>\n	<li>Regenwasser das nicht auf der Parzelle gesammelt wird, oberflächlich in den Boden einsickern lassen.</li>\n	<li>Für Wildtiere: Zuhause, Futter und Nistmöglichkeiten schaffen. Nur dann können sie ihre Lebenskreisläufe schließen und überleben.</li>\n</ul>\n\n<h6>Genussmomente!</h6>\n\n<ul>\n	<li>Super für Insekten: Salat, Kohl, Allium-Gewächse (Wie Lauch), Kräuter etc. ausblühen lassen. Essbar für Menschen und Insekten!</li>\n	<li>Naschsäume für die Menschen</li>\n	<li>Entspannen und TV schauen: Regen TV, Vogel TV, Insekten TV, ..... Deep Reality, die entspannt.</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2240', '<ul>\n	<li>\n	<p>Auf der Webseite beschreibe ich Dinge die wie ich sehe den Wald vor lauter Bäumen nicht mehr sind, lauter fingerzeige und Beispiele die eigentlich viel das gleiche Aussagen in unterschiedlichsten Perspektiven. Ich möchte dass wir eine Kultur entwickeln und das braucht Tiefe Inspiration viele Geschichten, etwas wo sich jeder Mensch wiederfinden kann und eben simples</p>\n	</li>\n	<li>\n	<p>Dragon Dreaming ein Jahr Arbeit</p>\n	</li>\n	<li>\n	<p>Inklusiv: möglichst einfache Sprache, reizreduziert. Und doch mit viel Spaß um lebensnah Permakultur zu erklären.</p>\n	</li>\n	<li>\n	<p>Wie ein Netzwerk aufgebaut, Du kannst an der oberfläche bleiben oder ganz tief tauchen.</p>\n	</li>\n	<li>\n	<p>Ich möchte zur professionalisierung von Permakultur beitragen</p>\n	</li>\n	<li>\n	<p>Denn es ist nicht wichtig was genau wir tun. Es ist nur wichtig, dass wir es mit Freude tun!</p>\n	</li>\n	<li>\n	<p>Ausgangsimpuls Die WElt ist vller Möglichketen!.....</p>\n	</li>\n	<li>\n	<p>Nadine getroffen beim Kurs von Sina.</p>\n	</li>\n	<li>\n	<p>Die Idee einer Webseite hat sich um 180 Grad gedreht, von einer einfachen Kontaktwebseite zu einem Fundus, ERklärwerk und eigenem Kunstwerk. Das Kunstwerk des natürlichen Lebens. Finde heraus, was genau das für Dich bedeutet! Viel Spaß beim reinlesen....</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2243', '<p>zum Beispiel durch:</p>\n\n<ul>\n	<li>Humusaufbau und Bodenpflege: #Mulch-Liebe, Kreislaufwirtschaft, Regenwürmer füttern, Gründüngung, ...</li>\n	<li>Vielfalt im naturnahen Garten fördern: Obstbaumgilde, essbarer Waldgarten, Kleinstbiotope, Wildtierhabitaten und seltene heimische Pflanzen</li>\n	<li>Ressourcenbewusstsein und Kreisläufe schließen</li>\n</ul>', '');
