INSERT INTO `fields` (`id`, `type`, `name`, `flags`, `label`, `data`) VALUES('130', 'FieldtypeText', 'date_start', '0', 'Startdatum', '{\"label1025\":\"Start date\",\"description\":\"Gebe hier das Startdatum und ggf. -zeit im Format dd.mm.YYYY, HH:MMh ein. Beachte dies unbedingt, um Diskrepanzen \\u00fcber Seiten hinweg zu vermeiden.\",\"notes\":\"Bsp: 01.01.2026, 18:00h\\nInfo: Wir nutzen hier \\\"h\\\" anstatt \\\"Uhr, um f\\u00fcr Mehrsprachigkeit ger\\u00fcstet zu sein.\\nDer Bindestrich zwischen den Daten wird automatisch eingef\\u00fcgt.\",\"textformatters\":[\"TextformatterEntities\"],\"collapsed\":0,\"minlength\":0,\"maxlength\":18,\"showCount\":1,\"size\":0,\"placeholder\":\"01.01.2026, 18:00h\",\"columnWidth\":50,\"stripTags\":1}');
