INSERT INTO `fields` (`id`, `type`, `name`, `flags`, `label`, `data`) VALUES('136', 'FieldtypeText', 'alt_text', '0', 'Beschreibung', '{\"label1025\":\"Description\",\"textformatters\":[\"TextformatterEntities\"],\"collapsed\":0,\"minlength\":0,\"maxlength\":150,\"showCount\":1,\"size\":0,\"notes\":\"Bsp. \\\"L\\u00e4chelnde Barista serviert Kaffee\\\"\",\"description\":\"Kurzer Text (max. 1 bis 2 S\\u00e4tze), der das Bild beschreibt. Sehr wichtig, denn Screenreader lesen diesen vor. Ausserdem wird dieser Text angezeigt, wenn das Bild nicht geladen werden kann.\",\"stripTags\":1}');
INSERT INTO `fields` (`id`, `type`, `name`, `flags`, `label`, `data`) VALUES('137', 'FieldtypeText', 'long_description', '0', 'Längere Beschreibung', '{\"label1025\":\"Long description\",\"textformatters\":[\"TextformatterEntities\"],\"collapsed\":0,\"minlength\":0,\"maxlength\":255,\"showCount\":1,\"size\":0,\"notes\":\"Bsp: \\\"Eine Barista mit gr\\u00fcnem Sch\\u00fcrzenkleid reicht einem Kunden eine Tasse Kaffee \\u00fcber die Theke in einem hellen Caf\\u00e9.\\\"\",\"description\":\"Zus\\u00e4tzliche l\\u00e4ngere Beschreibung (optional), falls die Beschreibung (alt-text) nicht reicht. Besonders n\\u00fctzlich f\\u00fcr Diagramme, Infografiken oder Kunstwerke.\",\"stripTags\":1}');
