INSERT INTO `fields` (`id`, `type`, `name`, `flags`, `label`, `data`) VALUES('146', 'FieldtypeTable', 'context', '0', 'Kontext', '{\"label1025\":\"Context\",\"maxCols\":2,\"col1name\":\"number\",\"col1label\":\"Nummer\",\"col1type\":\"int1\",\"col1width\":10,\"col1sort\":1,\"col1label1025\":\"Number\",\"col2name\":\"text\",\"col2label\":\"Text\",\"col2type\":\"textareaCKELanguage\",\"col2width\":90,\"col2sort\":2,\"col2label1025\":\"Text\",\"col3sort\":3,\"paginationLimit\":0,\"collapsed\":0,\"col1settings\":\"min=\\nmax=\",\"col2settings\":\"settingsField=text\\nuseACF=1\\nusePurifier=1\\ninherit=1\\nrows=4\\ntextformatters=CKEditor\\nplaceholder=\\ndefault=\",\"addRowLabel\":\"Eintrag hinzuf\\u00fcgen\",\"addRowLabel1025\":\"Add entry\",\"orderByCols\":[\"number\"],\"description\":\"F\\u00fcge hier Nummer und Inhalt der Fussnoten hinzu, falls du im Inhaltsblock im Text welche gesetzt hast. Achte darauf, dass die numerische Zuordnung stimmt. Die Reihenfolge wird nach dem Speichern automatisch absteigend sortiert. Diese Sektion wird zudem unter \\\"Kontext\\\" angezeigt.\",\"notes\":\"Beschr\\u00e4nke dich hier auf Text mit Formatierungen und Links.\"}');
INSERT INTO `fields` (`id`, `type`, `name`, `flags`, `label`, `data`) VALUES('147', 'FieldtypeCheckbox', 'is_overview_category', '0', 'Kategorie auf Übersichtsseite', '{\"description\":\"Diese Auswahl legt fest, ob diese Kategorie auf der \\u00dcbersichtsseite Werkzeugpalette angezeigt werden soll. Beachte, dass du max. 8 Kategorien ausw\\u00e4hlen und zeigen kannst.\",\"notes\":\"Weise diesen Wert hier allen (max. 8) Kategorien zu, die auf der \\u00dcbersichtsseite dargestellt werden sollen.\",\"collapsed\":0,\"requiredIf\":\"select_context=1257\",\"showIf\":\"select_context%=1257\"}');
INSERT INTO `fields` (`id`, `type`, `name`, `flags`, `label`, `data`) VALUES('148', 'FieldtypePage', 'select_host', '0', 'Nur für Akkordions: Auswahl der Elternseite', '{\"label1025\":\"Only for accordions: select a parent\",\"derefAsPage\":2,\"inputfield\":\"_InputfieldTextTags\",\"distinctAutojoin\":true,\"operator\":\"%=\",\"searchFields\":\"title\",\"parent_id\":0,\"labelFieldName\":\".\",\"collapsed\":0,\"optionColumns\":0,\"useAjax\":0,\"allowUserTags\":0,\"closeAfterSelect\":1,\"maxItems\":1,\"labelFieldFormat\":\"{title} ({path})\",\"template_id\":52,\"template_ids\":[77,64,70,65,72,66,78,73,74,49,75,76,29],\"findPagesSelector\":\"sort=title\",\"description\":\"Falls du oben ein Akkordion ausgew\\u00e4hlt hast: w\\u00e4hle die Seite, auf der das Akkordion eingebunden wurde, aus dem Dropdown-Men\\u00fc. Die Links sind alphabetisch sortiert und zeigen zu besseren Orientierung ihren Titel und Pfad an. Im Auswahlfeld kannst du zudem auch nach einem Link suchen.\",\"notes\":\"Dies ist wichtig, um den korrekten Link f\\u00fcr das Frontend zu generieren: accordions\\/xxx wird zu elternseite\\/des\\/akkordions\\/xxx. Achte darauf, das Akkordion zuerst auf der Seite einzubinden, bevor du auf es verlinken m\\u00f6chtest. Bsp: du hast ein Akkordion \\\"Test-Akkordion\\\" erstellt und auf Beratung (\\/angebote\\/beratung\\/) eingebunden. Nun w\\u00e4hlst du hier Beratung aus.\"}');
